import assert from "node:assert/strict";
import { readFileSync } from "node:fs";
import { join } from "node:path";
import { describe, it } from "node:test";
import { repoRoot } from "../../test/fixture-paths.js";
import { CompilePhase } from "../domain/compile-phase.js";
import { DiagnosticSeverity } from "../domain/diagnostic-code.js";
import { BoundNodeKind } from "../domain/bound-tree.js";
import { IrMerge } from "../domain/ir-merge.js";
import { FsRegistryLoader } from "../adapters/fs-registry-loader.js";
import { TomlLockReader } from "../adapters/toml-lock-reader.js";
import { parseSyntaxTree } from "../passes/parse/recursive-descent-parser.js";
import { CompilePipeline } from "./compile-pipeline.js";

const relayWorkspace = join(repoRoot, "test/fixtures/workspace/relay");
const relayProductSource = readFileSync(join(relayWorkspace, "product.pactia"), "utf8");
const relayMonolithSource = readFileSync(join(repoRoot, "test/fixtures/kernel/relay.pactia"), "utf8");
const testIrWorkspace = join(repoRoot, "test/fixtures/workspace/test-ir");

describe("CompilePipeline v2 wiring", () => {
  it("runs through parse and resolve-packages on relay workspace", () => {
    const previous = process.env["PACTIA_VENDOR_ROOT"];
    process.env["PACTIA_VENDOR_ROOT"] = join(repoRoot, "test/fixtures/packages");
    try {
      const pipeline = new CompilePipeline({
        stopAfterPhase: CompilePhase.ResolvePackages,
        ports: {
          parser: { parse: (input) => parseSyntaxTree(input) },
          registryLoader: new FsRegistryLoader(),
          lockReader: new TomlLockReader(),
          irEmitter: { emit: () => ({ writtenPaths: [] }) },
        },
      });

      const result = pipeline.run({
        workspaceRoot: relayWorkspace,
        entryFile: "product.pactia",
        source: relayProductSource,
      });

      assert.equal(result.diagnostics.length, 0);
      assert.ok(result.syntax);
      assert.equal(result.syntax.root.product?.name, "Relay");
      assert.ok(result.registry.macros.has("paginated"));
    } finally {
      if (previous === undefined) delete process.env["PACTIA_VENDOR_ROOT"];
      else process.env["PACTIA_VENDOR_ROOT"] = previous;
    }
  });

  it("runs bind phase on relay monolith and attaches stack macros", () => {
    const previous = process.env["PACTIA_VENDOR_ROOT"];
    process.env["PACTIA_VENDOR_ROOT"] = join(repoRoot, "test/fixtures/packages");
    try {
      const pipeline = new CompilePipeline({
        stopAfterPhase: CompilePhase.Bind,
        ports: {
          parser: { parse: (input) => parseSyntaxTree(input) },
          registryLoader: new FsRegistryLoader(),
          lockReader: new TomlLockReader(),
          irEmitter: { emit: () => ({ writtenPaths: [] }) },
        },
      });

      const result = pipeline.run({
        workspaceRoot: relayWorkspace,
        entryFile: "product.pactia",
        source: relayMonolithSource,
      });

      assert.ok(result.bound);
      assert.equal(result.bound.root.hostName, "Relay");
      const ordersModule = result.bound.root.children.find(
        (child) => child.kind === BoundNodeKind.BoundBlock && child.hostName === "orders",
      );
      assert.ok(ordersModule);
      assert.equal(result.diagnostics.length, 0);
    } finally {
      if (previous === undefined) delete process.env["PACTIA_VENDOR_ROOT"];
      else process.env["PACTIA_VENDOR_ROOT"] = previous;
    }
  });

  it("expands stack macros through expand-macros phase on relay service", () => {
    const previous = process.env["PACTIA_VENDOR_ROOT"];
    process.env["PACTIA_VENDOR_ROOT"] = join(repoRoot, "test/fixtures/packages");
    try {
      const pipeline = new CompilePipeline({
        stopAfterPhase: CompilePhase.ExpandMacros,
        ports: {
          parser: { parse: (input) => parseSyntaxTree(input) },
          registryLoader: new FsRegistryLoader(),
          lockReader: new TomlLockReader(),
          irEmitter: { emit: () => ({ writtenPaths: [] }) },
        },
      });

      const result = pipeline.run({
        workspaceRoot: relayWorkspace,
        entryFile: "product.pactia",
        source: relayMonolithSource,
      });

      assert.ok(result.bound);
      const ordersModule = result.bound.root.children.find(
        (child) => child.kind === BoundNodeKind.BoundBlock && child.hostName === "orders",
      );
      assert.ok(ordersModule && ordersModule.kind === BoundNodeKind.BoundBlock);
      const orderService = ordersModule.children.find(
        (child) => child.kind === BoundNodeKind.BoundBlock && child.hostName === "OrderService",
      );
      assert.ok(orderService && orderService.kind === BoundNodeKind.BoundBlock);

      const listEndpointPrep = orderService.children.filter(
        (child) =>
          child.kind === BoundNodeKind.BoundTag &&
          child.hostId === "list_orders" &&
          child.registryEntry.ir.merge === IrMerge.AppendHost,
      );
      assert.ok(listEndpointPrep.length >= 1);
    } finally {
      if (previous === undefined) delete process.env["PACTIA_VENDOR_ROOT"];
      else process.env["PACTIA_VENDOR_ROOT"] = previous;
    }
  });

  it("lowers through lower phase with test-ir registry tags", () => {
    const previous = process.env["PACTIA_VENDOR_ROOT"];
    process.env["PACTIA_VENDOR_ROOT"] = join(repoRoot, "test/fixtures/packages");
    try {
      const source = `pactia 1.0
import @pactia/test-ir;

product Demo {
  module billing {
    service OrderService {
      @output OrderResponse
      @api create_order {
        method: POST,
        path: "/api/v1/orders",
      }
    }
  }
}`;

      const pipeline = new CompilePipeline({
        stopAfterPhase: CompilePhase.Lower,
        ports: {
          parser: { parse: (input) => parseSyntaxTree(input) },
          registryLoader: new FsRegistryLoader(),
          lockReader: new TomlLockReader(),
          irEmitter: { emit: () => ({ writtenPaths: [] }) },
        },
      });

      const result = pipeline.run({
        workspaceRoot: testIrWorkspace,
        entryFile: "product.pactia",
        source,
      });

      const errors = result.diagnostics.filter((d) => d.severity === DiagnosticSeverity.Error);
      assert.equal(errors.length, 0, errors.map((d) => d.message).join("; "));
      assert.ok(result.lowered);
      assert.ok(result.files.get("input/modules/billing/services/order.service.json"));
    } finally {
      if (previous === undefined) delete process.env["PACTIA_VENDOR_ROOT"];
      else process.env["PACTIA_VENDOR_ROOT"] = previous;
    }
  });
});

import { readFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

export enum TestFixtureId {
  Relay = "relay",
}

const FIXTURE_RELATIVE: Record<TestFixtureId, string> = {
  [TestFixtureId.Relay]: "kernel/relay.pactia",
};

const testDir = dirname(fileURLToPath(import.meta.url));

/** Repository root (package.json, src/, test/). */
export const repoRoot = resolve(testDir, "..");

export function resolveTestFixture(id: TestFixtureId): string {
  const path = resolve(testDir, "fixtures", FIXTURE_RELATIVE[id]);
  return path;
}

export function readTestFixture(id: TestFixtureId): string {
  return readFileSync(resolveTestFixture(id), "utf8");
}

/** Normative compile phases — spec/docs/compilation.md (0–11). */
export enum CompilePhase {
  AssembleWorkspace = 0,
  ValidateVersion = 1,
  Lex = 2,
  Parse = 3,
  ResolvePackages = 4,
  MergeDeclarations = 5,
  Bind = 6,
  ExpandMacros = 7,
  Validate = 8,
  CrossCheck = 9,
  Lower = 10,
  Infer = 11,
  Emit = 12,
}

export const compilePhaseOrder: readonly CompilePhase[] = [
  CompilePhase.AssembleWorkspace,
  CompilePhase.ValidateVersion,
  CompilePhase.Lex,
  CompilePhase.Parse,
  CompilePhase.ResolvePackages,
  CompilePhase.MergeDeclarations,
  CompilePhase.Bind,
  CompilePhase.ExpandMacros,
  CompilePhase.Validate,
  CompilePhase.CrossCheck,
  CompilePhase.Lower,
  CompilePhase.Infer,
  CompilePhase.Emit,
];

export function compilePhaseLabel(phase: CompilePhase): string {
  switch (phase) {
    case CompilePhase.AssembleWorkspace:
      return "assemble-workspace";
    case CompilePhase.ValidateVersion:
      return "validate-version";
    case CompilePhase.Lex:
      return "lex";
    case CompilePhase.Parse:
      return "parse";
    case CompilePhase.ResolvePackages:
      return "resolve-packages";
    case CompilePhase.MergeDeclarations:
      return "merge-declarations";
    case CompilePhase.Bind:
      return "bind";
    case CompilePhase.ExpandMacros:
      return "expand-macros";
    case CompilePhase.Validate:
      return "validate";
    case CompilePhase.CrossCheck:
      return "cross-check";
    case CompilePhase.Lower:
      return "lower";
    case CompilePhase.Infer:
      return "infer";
    case CompilePhase.Emit:
      return "emit";
    default: {
      const _exhaustive: never = phase;
      return _exhaustive;
    }
  }
}

/** Compiler diagnostic codes — normative subset from spec/docs/grammar-reference.md. */
export enum DiagnosticCode {
  // Registry
  UnknownSymbol = "UNKNOWN_SYMBOL",
  DefInProduct = "DEF_IN_PRODUCT",
  DefPlacementRequired = "DEF_PLACEMENT_REQUIRED",
  PlacementViolation = "PLACEMENT_VIOLATION",
  RegistryCollision = "REGISTRY_COLLISION",
  DependencyNotDeclared = "DEPENDENCY_NOT_DECLARED",
  VersionInImport = "VERSION_IN_IMPORT",
  MacroUnknown = "MACRO_UNKNOWN",
  MacroArgsInvalid = "MACRO_ARGS_INVALID",
  MacroExpansionCycle = "MACRO_EXPANSION_CYCLE",
  MacroExpansionInvalid = "MACRO_EXPANSION_INVALID",

  // Tag bodies
  TagBodyMissingField = "TAG_BODY_MISSING_FIELD",
  TagBodyUnknownField = "TAG_BODY_UNKNOWN_FIELD",
  TagBodyInvalid = "TAG_BODY_INVALID",
  ClauseDuplicateKey = "CLAUSE_DUPLICATE_KEY",

  // Package resolution
  PackageNotFound = "PACKAGE_NOT_FOUND",
  PackageLockMismatch = "PACKAGE_LOCK_MISMATCH",
  LockEntryMissing = "LOCK_ENTRY_MISSING",

  // Version / parse
  UnsupportedVersion = "UNSUPPORTED_VERSION",
  ParseError = "PARSE_ERROR",
  ConstantUndefined = "CONSTANT_UNDEFINED",

  // Workspace attach
  ImportUnused = "IMPORT_UNUSED",
  AttachUndefined = "ATTACH_UNDEFINED",
  AttachKindMismatch = "ATTACH_KIND_MISMATCH",
  ContextImportUnused = "CONTEXT_IMPORT_UNUSED",
  ContextAttachUndefined = "CONTEXT_ATTACH_UNDEFINED",
  ContextAttachKindMismatch = "CONTEXT_ATTACH_KIND_MISMATCH",
  ContextMissingPath = "CONTEXT_MISSING_PATH",
  FragmentPackageImport = "FRAGMENT_PACKAGE_IMPORT",

  // Package constants
  ConstantDefRequired = "CONSTANT_DEF_REQUIRED",
  ExportKindAmbiguity = "EXPORT_KIND_AMBIGUITY",
}

export enum DiagnosticSeverity {
  Error = "error",
  Warning = "warning",
}

/** Codes that represent warnings rather than hard errors. */
export const diagnosticWarningCodes: ReadonlySet<DiagnosticCode> = new Set([
  DiagnosticCode.TagBodyMissingField,
  DiagnosticCode.TagBodyUnknownField,
  DiagnosticCode.ClauseDuplicateKey,
  DiagnosticCode.ImportUnused,
  DiagnosticCode.FragmentPackageImport,
]);

export function defaultSeverityForCode(code: DiagnosticCode): DiagnosticSeverity {
  return diagnosticWarningCodes.has(code)
    ? DiagnosticSeverity.Warning
    : DiagnosticSeverity.Error;
}

import type { PlacementTarget } from "./placement.js";
import type { RegistryEntry, RegistryMacroEntry, RegistryTagEntry } from "./registry.js";
import type {
  ContextBlockNode,
  FieldLineNode,
  ModuleConstNode,
  ProseNode,
  SourceLocation,
} from "./syntax-tree.js";

export interface LocatedNode {
  readonly location: SourceLocation;
}

/** L1 items — bound nodes plus unannotated L0 leaves carried through bind. */
export type BoundTreeItem =
  | BoundNode
  | FieldLineNode
  | ProseNode
  | ModuleConstNode
  | ContextBlockNode;

/** L1 bound tree — L0 nodes annotated with resolved registry entries. */
export enum BoundNodeKind {
  BoundTag = "bound-tag",
  BoundMacro = "bound-macro",
  BoundBlock = "bound-block",
  BoundDef = "bound-def",
  BoundContext = "bound-context",
}

export interface BoundContextNode extends LocatedNode {
  readonly kind: BoundNodeKind.BoundContext;
  readonly name: string;
  readonly path: string | readonly string[];
  readonly guidance: readonly string[];
  /** Set when path is relative to a vendored package root. */
  readonly packageCoordinate?: string;
}

export interface BoundTagNode extends LocatedNode {
  readonly kind: BoundNodeKind.BoundTag;
  readonly tagName: string;
  readonly hostId?: string;
  readonly shorthand?: string;
  readonly registryEntry: RegistryTagEntry;
  readonly enclosing: PlacementTarget;
  readonly children: readonly BoundTreeItem[];
}

export interface BoundMacroNode extends LocatedNode {
  readonly kind: BoundNodeKind.BoundMacro;
  readonly name: string;
  readonly registryEntry: RegistryMacroEntry;
  readonly enclosing: PlacementTarget;
  readonly args: readonly string[];
}

export interface BoundBlockNode extends LocatedNode {
  readonly kind: BoundNodeKind.BoundBlock;
  readonly placement: PlacementTarget;
  readonly hostName?: string;
  readonly children: readonly BoundTreeItem[];
}

export interface BoundDefNode extends LocatedNode {
  readonly kind: BoundNodeKind.BoundDef;
  readonly name: string;
  readonly exported: boolean;
  readonly registryEntry: RegistryEntry;
}

export type BoundNode = BoundTagNode | BoundMacroNode | BoundBlockNode | BoundDefNode | BoundContextNode;

export interface BoundTree {
  readonly entryFile: string;
  readonly root: BoundBlockNode;
}

export function boundNodeLocation(node: BoundNode): SourceLocation {
  return node.location;
}

/** Tag lowering merge strategy — spec/docs/compilation.md#tag-lowering. */
export enum IrMerge {
  AppendHost = "append_host",
  MergeIntoHost = "merge_into_host",
  MergeFields = "merge_fields",
  FieldAnnotation = "field_annotation",
}

export const irMergeValues: readonly IrMerge[] = Object.values(IrMerge) as IrMerge[];

export function parseIrMerge(value: string): IrMerge | undefined {
  return irMergeValues.find((merge) => merge === value);
}

import { existsSync, readFileSync } from "node:fs";
import { join, resolve } from "node:path";
import {
  RegistryPrecedenceTier,
  registryPrecedenceOrder,
  type EffectiveRegistry,
} from "../domain/registry.js";
import { collectLocalDefs, programModules, type SyntaxTree } from "../domain/syntax-tree.js";
import type { RegistryLoaderInput, RegistryLoaderSync } from "../ports/registry-loader.js";
import { loadVendoredPackage, type LoadedPackage } from "../resolve/loader.js";
import {
  assertImportsDeclared,
  assertLockEntries,
  parsePactiaLock,
  parsePactiaToml,
} from "../resolve/manifest.js";
import { parseSyntaxTree } from "../passes/parse/recursive-descent-parser.js";
import {
  constantsFromProgram,
  mergeEffectiveRegistry,
  registryEntriesFromLocalDefs,
  registryEntriesFromProgram,
  contextExportsFromProgram,
  filterContextExports,
} from "../passes/registry/build-effective-registry.js";
import { applyPartialImportFilter } from "../passes/registry/import-symbol.js";

const INDEX_FILE = "index.pactia";
const TOML_FILE = "pactia.toml";
const LOCK_FILE = "pactia.lock";

function readOptional(path: string): string | undefined {
  return existsSync(path) ? readFileSync(path, "utf8") : undefined;
}

function tierRank(tier: RegistryPrecedenceTier): number {
  return registryPrecedenceOrder.indexOf(tier);
}

export class FsRegistryLoader implements RegistryLoaderSync {
  load(input: RegistryLoaderInput): EffectiveRegistry {
    const tomlSource = readOptional(join(input.workspaceRoot, TOML_FILE));
    const lockSource = readOptional(join(input.workspaceRoot, LOCK_FILE));
    const imports = input.importCoordinates;

    const importPackages: LoadedPackage[] = [];

    if (tomlSource && lockSource) {
      const toml = parsePactiaToml(tomlSource);
      const lock = parsePactiaLock(lockSource);
      assertImportsDeclared(imports, toml);

      const coordinates = [...new Set(imports)];
      assertLockEntries(coordinates, lock);

      for (const coordinate of coordinates) {
        const entry = lock.packages.find((pkg) => pkg.name === coordinate)!;
        importPackages.push(loadVendoredPackage(input.workspaceRoot, coordinate, entry));
      }
    }

    const importEntries = importPackages.map((pkg) => {
      const indexSource = readOptional(join(pkg.rootDir, INDEX_FILE));
      const program = indexSource
        ? parseSyntaxTree({ source: indexSource, entryFile: INDEX_FILE }).root
        : undefined;
      const parsed = program
        ? registryEntriesFromProgram(program, pkg.coordinate)
        : { tags: [], macros: [] };

      const partialSymbols = input.macroExpansion
        ? undefined
        : input.partialImports?.get(pkg.coordinate);
      const filtered = applyPartialImportFilter(parsed.tags, parsed.macros, partialSymbols);
      const contextExports = filterContextExports(
        program ? contextExportsFromProgram(program, pkg.coordinate) : [],
        partialSymbols,
      );

      const tier = imports.includes(pkg.coordinate)
        ? RegistryPrecedenceTier.ExplicitImport
        : RegistryPrecedenceTier.Dependency;

      const allConstants = program
        ? constantsFromProgram(program)
        : [];

      return {
        coordinate: pkg.coordinate,
        tier,
        tags: filtered.tags,
        macros: filtered.macros,
        contexts: contextExports,
        constants: new Map(
          (partialSymbols
            ? allConstants.filter((c) => partialSymbols.includes(c.name))
            : allConstants
          ).map((c) => [c.name, c.value] as const),
        ),
      };
    });

    importEntries.sort((left, right) => tierRank(left.tier) - tierRank(right.tier));

    const localDefs = input.syntax ? collectLocalDefs(programModules(input.syntax)) : [];
    const local = registryEntriesFromLocalDefs(localDefs, "local");

    return mergeEffectiveRegistry({
      importEntries,
      localTags: local.tags,
      localMacros: local.macros,
    });
  }
}

export function loadRegistryFromWorkspace(
  workspaceRoot: string,
  syntax: SyntaxTree,
): EffectiveRegistry {
  const imports = syntax.root.imports
    .map((node) => node.path)
    .filter((path) => path.startsWith("@"));
  const partialImports = new Map<string, readonly string[]>();
  for (const node of syntax.root.imports) {
    if (node.path.startsWith("@") && node.symbols && node.symbols.length > 0) {
      partialImports.set(node.path, node.symbols);
    }
  }
  return new FsRegistryLoader().load({
    workspaceRoot: resolve(workspaceRoot),
    importCoordinates: imports,
    syntax,
    partialImports,
  });
}

import type { IrFile } from "./ir-file.js";
import type { IrMerge } from "./ir-merge.js";
import type { PlacementTarget } from "./placement.js";

/** Parsed field spec from a `def @` body — required names, modifier flag, open extensions. */
export interface FieldSpec {
  readonly required: readonly string[];
  readonly optional: readonly string[];
  readonly modifier: boolean;
  readonly openExtension: boolean;
}

/** IR slot metadata attached at package build — read during lower (M5). */
export interface IrSlot {
  readonly file: IrFile;
  readonly path: string;
  readonly merge: IrMerge;
}

export enum RegistryEntryKind {
  Tag = "tag",
  Macro = "macro",
}

export interface RegistryTagEntry {
  readonly kind: RegistryEntryKind.Tag;
  readonly name: string;
  readonly source: string;
  readonly in: readonly PlacementTarget[];
  readonly fields: FieldSpec;
  readonly modifier: boolean;
  readonly ir: IrSlot;
}

import type { TagBodyItem } from "./syntax-tree.js";

/** Parsed macro/tag def body — structured items from the parse pass. */
export interface DefBodyAst {
  readonly lines: readonly string[];
  readonly items: readonly TagBodyItem[];
}

export interface RegistryMacroEntry {
  readonly kind: RegistryEntryKind.Macro;
  readonly name: string;
  readonly source: string;
  readonly in: readonly PlacementTarget[];
  readonly params: readonly string[];
  readonly body: DefBodyAst;
}

export type RegistryEntry = RegistryTagEntry | RegistryMacroEntry;

export interface PackageContextExport {
  readonly name: string;
  readonly coordinate: string;
  readonly pathRaw?: string;
  readonly guidance: readonly string[];
}

/** Resolved symbol table for one compile — imported packages and local defs merged. */
export interface EffectiveRegistry {
  readonly tags: ReadonlyMap<string, RegistryTagEntry>;
  readonly macros: ReadonlyMap<string, RegistryMacroEntry>;
  readonly contexts: ReadonlyMap<string, PackageContextExport>;
  /** Package-exported constants resolved from `export def name = value`. */
  readonly constants: ReadonlyMap<string, string>;
}

export enum RegistryPrecedenceTier {
  Local = "local",
  Dependency = "dependency",
  ExplicitImport = "explicit-import",
}

/** Precedence order (low → high): dependency < explicit import; local is lowest. */
export const registryPrecedenceOrder: readonly RegistryPrecedenceTier[] = [
  RegistryPrecedenceTier.Local,
  RegistryPrecedenceTier.Dependency,
  RegistryPrecedenceTier.ExplicitImport,
];

export function isRegistryTagEntry(entry: RegistryEntry): entry is RegistryTagEntry {
  return entry.kind === RegistryEntryKind.Tag;
}

export function isRegistryMacroEntry(entry: RegistryEntry): entry is RegistryMacroEntry {
  return entry.kind === RegistryEntryKind.Macro;
}

import type { PlacementTarget } from "./placement.js";

/** Source span for diagnostics — byte offsets into assembled workspace text. */
export interface SourceSpan {
  readonly start: number;
  readonly end: number;
}

export interface SourceLocation {
  readonly file: string;
  readonly line: number;
  readonly col: number;
  readonly span?: SourceSpan;
}

export enum SyntaxNodeKind {
  Workspace = "workspace",
  Product = "product",
  Module = "module",
  AttachModule = "attach-module",
  AttachService = "attach-service",
  Model = "model",
  Service = "service",
  TagBlock = "tag-block",
  TagPrefix = "tag-prefix",
  MacroInvocation = "macro-invocation",
  DefExport = "def-export",
  DefLocal = "def-local",
  ModuleConst = "module-const",
  PackageConst = "package-const",
  FieldLine = "field-line",
  Prose = "prose",
  Import = "import",
  Context = "context",
  ContextAttach = "context-attach",
}

export enum DefSigil {
  Tag = "tag",
  Macro = "macro",
}

export interface ContextBlockNode {
  readonly kind: SyntaxNodeKind.Context;
  readonly name: string;
  readonly exported: boolean;
  readonly path?: string;
  readonly pathRaw?: string;
  readonly guidance: readonly string[];
  readonly location: SourceLocation;
}

export interface ContextAttachNode {
  readonly kind: SyntaxNodeKind.ContextAttach;
  readonly symbol: string;
  readonly location: SourceLocation;
}

export interface ImportNode {
  readonly kind: SyntaxNodeKind.Import;
  readonly path: string;
  readonly symbols?: readonly string[];
  readonly location: SourceLocation;
}

export interface ProseNode {
  readonly kind: SyntaxNodeKind.Prose;
  readonly text: string;
  readonly multiline: boolean;
  readonly location: SourceLocation;
}

export interface FieldLineNode {
  readonly kind: SyntaxNodeKind.FieldLine;
  readonly name: string;
  readonly value?: string;
  readonly required: boolean;
  readonly location: SourceLocation;
}

export interface TagBlockNode {
  readonly kind: SyntaxNodeKind.TagBlock;
  readonly tagName: string;
  readonly hostId?: string;
  readonly items: readonly TagBodyItem[];
  readonly location: SourceLocation;
}

export interface TagPrefixNode {
  readonly kind: SyntaxNodeKind.TagPrefix;
  readonly tagName: string;
  readonly shorthand?: string;
  readonly modifier: boolean;
  readonly location: SourceLocation;
}

export interface MacroInvocationNode {
  readonly kind: SyntaxNodeKind.MacroInvocation;
  readonly name: string;
  readonly args: readonly string[];
  readonly location: SourceLocation;
}

export type TagBodyItem =
  | FieldLineNode
  | ProseNode
  | TagBlockNode
  | TagPrefixNode
  | MacroInvocationNode;

export interface DefDeclNode {
  readonly kind: SyntaxNodeKind.DefExport | SyntaxNodeKind.DefLocal;
  readonly exported: boolean;
  readonly sigil: DefSigil;
  readonly name: string;
  readonly params: readonly string[];
  readonly inTargets: readonly PlacementTarget[];
  readonly modifier: boolean;
  readonly bodyItems: readonly TagBodyItem[];
  readonly bodySource: string;
  readonly location: SourceLocation;
}

export interface ModuleConstNode {
  readonly kind: SyntaxNodeKind.ModuleConst;
  readonly name: string;
  readonly value: string;
  readonly location: SourceLocation;
}

/** Exported package constant at file root: `export def name = value`. */
export interface PackageConstNode {
  readonly kind: SyntaxNodeKind.PackageConst;
  readonly name: string;
  readonly value: string;
  /** Whether `def` keyword was present. `false` for bare `export name = value`. */
  readonly hasDef: boolean;
  readonly location: SourceLocation;
}

export interface ServiceNode {
  readonly kind: SyntaxNodeKind.Service;
  readonly name: string;
  readonly items: readonly ServiceItem[];
  readonly location: SourceLocation;
}

export interface ModelNode {
  readonly kind: SyntaxNodeKind.Model;
  readonly name?: string;
  readonly items: readonly ModelItem[];
  readonly location: SourceLocation;
}

export type ServiceItem =
  | TagBlockNode
  | TagPrefixNode
  | MacroInvocationNode
  | ProseNode
  | FieldLineNode
  | ModuleConstNode
  | ContextBlockNode
  | ContextAttachNode;
export type ModelItem =
  | TagBlockNode
  | TagPrefixNode
  | MacroInvocationNode
  | ProseNode
  | FieldLineNode
  | ContextBlockNode
  | ContextAttachNode;
export type ModuleItem =
  | TagBlockNode
  | TagPrefixNode
  | MacroInvocationNode
  | ProseNode
  | FieldLineNode
  | ServiceNode
  | ModelNode
  | DefDeclNode
  | ModuleConstNode
  | ContextBlockNode
  | ContextAttachNode;

export type ProductItem =
  | TagBlockNode
  | TagPrefixNode
  | MacroInvocationNode
  | ProseNode
  | FieldLineNode
  | ModuleNode
  | AttachModuleNode
  | ContextBlockNode
  | ContextAttachNode;

export interface AttachServiceNode {
  readonly kind: SyntaxNodeKind.AttachService;
  readonly name: string;
  readonly modelSymbol?: string;
  readonly contextSymbols: readonly string[];
  readonly location: SourceLocation;
}

export interface AttachModuleNode {
  readonly kind: SyntaxNodeKind.AttachModule;
  readonly name: string;
  readonly services: readonly AttachServiceNode[];
  readonly location: SourceLocation;
}

export interface ModuleNode {
  readonly kind: SyntaxNodeKind.Module;
  readonly name: string;
  readonly items: readonly ModuleItem[];
  readonly location: SourceLocation;
}

export interface ProductNode {
  readonly kind: SyntaxNodeKind.Product;
  readonly name: string;
  readonly items: readonly ProductItem[];
  readonly location: SourceLocation;
}

export interface ProgramNode {
  readonly kind: SyntaxNodeKind.Workspace;
  readonly version: string;
  readonly imports: readonly ImportNode[];
  readonly exportDefs: readonly DefDeclNode[];
  /** Fragment files: export module … { } at program root. */
  readonly fragmentExports: readonly ModuleNode[];
  /** Fragment files: export service … { } at program root. */
  readonly fragmentServiceExports: readonly ServiceNode[];
  /** Fragment files: export model … { } at program root. */
  readonly fragmentModelExports: readonly ModelNode[];
  /** Fragment files: export context … { } at program root. */
  readonly fragmentContextExports: readonly ContextBlockNode[];
  /** Package index: export def name = value at file root. */
  readonly constantExports: readonly PackageConstNode[];
  readonly product?: ProductNode;
  readonly location: SourceLocation;
}

export interface SyntaxTree {
  readonly version: string;
  readonly root: ProgramNode;
  readonly source: string;
  readonly entryFile: string;
}

export function collectLocalDefs(modules: readonly ModuleNode[]): DefDeclNode[] {
  const defs: DefDeclNode[] = [];
  for (const module of modules) {
    for (const item of module.items) {
      if (item.kind === SyntaxNodeKind.DefExport || item.kind === SyntaxNodeKind.DefLocal) {
        defs.push(item);
      }
    }
  }
  return defs;
}

export function programModules(tree: SyntaxTree): readonly ModuleNode[] {
  return tree.root.product?.items.filter((item): item is ModuleNode => item.kind === SyntaxNodeKind.Module) ?? [];
}

import { createHash } from "node:crypto";
import { existsSync, readFileSync } from "node:fs";
import { join, resolve } from "node:path";
import { PackageErrorCode, PackageResolutionError } from "./errors.js";
import type { PactiaLockManifest } from "./manifest.js";

export interface LoadedPackage {
  readonly coordinate: string;
  readonly version: string;
  readonly digest: string;
  readonly rootDir: string;
  readonly manifestSource: string | undefined;
  readonly indexSource: string | undefined;
}

function readOptional(path: string): string | undefined {
  return existsSync(path) ? readFileSync(path, "utf8") : undefined;
}

function vendorSearchRoots(workspaceRoot: string): string[] {
  const roots = [join(workspaceRoot, ".pactia", "packages")];
  if (process.env["PACTIA_VENDOR_ROOT"]) {
    roots.push(resolve(process.env["PACTIA_VENDOR_ROOT"]));
  }
  return roots;
}

function packageDirName(coordinate: string, version: string): string {
  return `${coordinate.replace(/\//g, "--")}@${version}`;
}

export function loadVendoredPackage(
  workspaceRoot: string,
  coordinate: string,
  lockEntry: PactiaLockManifest["packages"][number],
): LoadedPackage {
  for (const vendorRoot of vendorSearchRoots(workspaceRoot)) {
    const dir = join(vendorRoot, packageDirName(coordinate, lockEntry.version));
    if (!existsSync(dir)) continue;

    const manifestPath = join(dir, "pactia.toml");
    const tarballDigestPath = join(dir, ".digest");
    const onDiskDigest = readOptional(tarballDigestPath);
    if (onDiskDigest && onDiskDigest.trim() !== lockEntry.digest) {
      throw new PackageResolutionError(
        PackageErrorCode.PackageLockMismatch,
        `Digest mismatch for '${coordinate}': lock has ${lockEntry.digest}, vendor has ${onDiskDigest.trim()}`,
      );
    }

    return {
      coordinate,
      version: lockEntry.version,
      digest: lockEntry.digest,
      rootDir: dir,
      manifestSource: readOptional(manifestPath),
      indexSource: readOptional(join(dir, "index.pactia")),
    };
  }

  throw new PackageResolutionError(
    PackageErrorCode.PackageNotFound,
    `Vendored package '${coordinate}@${lockEntry.version}' not found under workspace vendor roots`,
  );
}

export function hashDirectoryMarker(rootDir: string): string {
  const marker = join(rootDir, ".digest");
  if (existsSync(marker)) {
    return readFileSync(marker, "utf8").trim();
  }
  const toml = readOptional(join(rootDir, "pactia.toml")) ?? "";
  const index = readOptional(join(rootDir, "index.pactia")) ?? "";
  const hash = createHash("sha256").update(toml, "utf8").update(index, "utf8").digest("hex");
  return `sha256:${hash}`;
}

export enum PackageErrorCode {
  PackageNotFound = "PACKAGE_NOT_FOUND",
  DependencyNotDeclared = "DEPENDENCY_NOT_DECLARED",
  LockEntryMissing = "LOCK_ENTRY_MISSING",
  PackageLockMismatch = "PACKAGE_LOCK_MISMATCH",
}

export class PackageResolutionError extends Error {
  constructor(
    readonly code: PackageErrorCode,
    message: string,
  ) {
    super(message);
    this.name = "PackageResolutionError";
  }
}

import { createHash } from "node:crypto";
import { parsePactiaLockToml } from "./toml-lock.js";
import { PackageErrorCode, PackageResolutionError } from "./errors.js";

export interface PactiaTomlManifest {
  readonly dependencies: ReadonlyMap<string, string>;
}

export interface PactiaLockManifest {
  readonly packages: ReadonlyArray<{
    readonly name: string;
    readonly version: string;
    readonly digest: string;
  }>;
}

export function parsePactiaToml(source: string): PactiaTomlManifest {
  const dependencies = new Map<string, string>();
  let section: "none" | "dependencies" = "none";

  for (const rawLine of source.split("\n")) {
    const line = rawLine.trim();
    if (line.length === 0 || line.startsWith("#")) continue;

    if (line === "[dependencies]") {
      section = "dependencies";
      continue;
    }
    if (line.startsWith("[")) {
      section = "none";
      continue;
    }

    const kv = /^([^=]+)=\s*(.+)$/.exec(line);
    if (!kv) continue;
    const key = kv[1]!.trim();
    const value = kv[2]!.trim().replace(/^["']|["']$/g, "");

    if (section === "dependencies") {
      dependencies.set(key.replace(/^["']|["']$/g, ""), value);
    }
  }

  return { dependencies };
}

export function parsePactiaLock(source: string): PactiaLockManifest {
  return parsePactiaLockToml(source);
}

export function lockfileDigest(source: string): string {
  const hash = createHash("sha256").update(source, "utf8").digest("hex");
  return `sha256:${hash}`;
}

export function normalizePackageCoordinate(coordinate: string): string {
  if (coordinate.startsWith("@")) return coordinate;
  return `@pactia/${coordinate}`;
}

export function assertImportsDeclared(
  imports: readonly string[],
  manifest: PactiaTomlManifest,
): void {
  for (const imp of imports) {
    if (!manifest.dependencies.has(imp)) {
      throw new PackageResolutionError(
        PackageErrorCode.DependencyNotDeclared,
        `Import '${imp}' is not declared in pactia.toml [dependencies]`,
      );
    }
  }
}

export function assertLockEntries(
  coordinates: readonly string[],
  lock: PactiaLockManifest,
): void {
  for (const coordinate of coordinates) {
    const entry = lock.packages.find((pkg) => pkg.name === coordinate);
    if (!entry) {
      throw new PackageResolutionError(
        PackageErrorCode.LockEntryMissing,
        `No lock entry for '${coordinate}' in pactia.lock`,
      );
    }
  }
}

import { PackageErrorCode, PackageResolutionError } from "./errors.js";
import type { PactiaLockManifest } from "./manifest.js";

interface LockPackageDraft {
  name?: string;
  version?: string;
  digest?: string;
}

function stripQuotes(value: string): string {
  return value.replace(/^["']|["']$/g, "");
}

function finalizePackage(
  draft: LockPackageDraft,
  index: number,
): PactiaLockManifest["packages"][number] {
  const { name, version, digest } = draft;
  if (typeof name !== "string" || typeof version !== "string" || typeof digest !== "string") {
    throw new PackageResolutionError(
      PackageErrorCode.LockEntryMissing,
      `pactia.lock [[package]] entry ${index} must include name, version, and digest`,
    );
  }
  return { name, version, digest };
}

/** Parse Cargo-style TOML lockfile — spec/docs/packages.md. */
export function parsePactiaLockToml(source: string): PactiaLockManifest {
  const packages: PactiaLockManifest["packages"][number][] = [];
  let lockVersion: number | undefined;
  let current: LockPackageDraft | undefined;
  let packageIndex = 0;

  for (const rawLine of source.split("\n")) {
    const line = rawLine.trim();
    if (line.length === 0 || line.startsWith("#")) continue;

    if (line === "[[package]]") {
      if (current) {
        packages.push(finalizePackage(current, packageIndex));
        packageIndex += 1;
      }
      current = {};
      continue;
    }

    const kv = /^([^=]+)=\s*(.+)$/.exec(line);
    if (!kv) continue;

    const key = kv[1]!.trim();
    const value = stripQuotes(kv[2]!.trim());

    if (key === "lockVersion") {
      lockVersion = Number(value);
      continue;
    }

    if (!current) continue;
    if (key === "name") current.name = value;
    if (key === "version") current.version = value;
    if (key === "digest") current.digest = value;
  }

  if (current) {
    packages.push(finalizePackage(current, packageIndex));
  }

  if (packages.length === 0) {
    throw new PackageResolutionError(
      PackageErrorCode.LockEntryMissing,
      "pactia.lock must contain at least one [[package]] entry",
    );
  }

  if (lockVersion !== undefined && lockVersion < 1) {
    throw new PackageResolutionError(
      PackageErrorCode.LockEntryMissing,
      "pactia.lock lockVersion must be >= 1",
    );
  }

  return { packages };
}

import {
  DefSigil,
  SyntaxNodeKind,
  type AttachModuleNode,
  type AttachServiceNode,
  type ContextAttachNode,
  type ContextBlockNode,
  type DefDeclNode,
  type FieldLineNode,
  type ImportNode,
  type MacroInvocationNode,
  type ModelItem,
  type ModelNode,
  type ModuleConstNode,
  type ModuleItem,
  type ModuleNode,
  type ProductItem,
  type ProductNode,
  type ProgramNode,
  type ProseNode,
  type ServiceItem,
  type ServiceNode,
  type SyntaxTree,
  type TagBlockNode,
  type TagBodyItem,
  type TagPrefixNode,
} from "../../domain/syntax-tree.js";
import { allPlacementTargets, parsePlacementTarget, type PlacementTarget } from "../../domain/placement.js";
import { collectContextGuidance } from "../../domain/context-path.js";
import type { FieldSpec } from "../../domain/registry.js";
import { tokenize, TokenType, PactiaSyntaxError } from "../../frontend/lexer/tokens.js";
import type { ParseInput } from "../../ports/parser.js";
import { isMacroInvocationStart, isModifierTagToken, isTagToken, tagNameFromToken, TokenStream } from "./token-stream.js";

export function fieldSpecFromDefBody(items: readonly TagBodyItem[]): FieldSpec {
  const required: string[] = [];
  const optional: string[] = [];
  let modifier = false;

  for (const item of items) {
    if (item.kind !== SyntaxNodeKind.FieldLine) continue;
    if (item.name === "modifier" && item.required) {
      modifier = true;
      continue;
    }
    if (item.required) required.push(item.name);
    else optional.push(item.name);
  }

  return { required, optional, modifier, openExtension: true };
}

export class RecursiveDescentParser {
  parse(input: ParseInput): SyntaxTree {
    const tokens = tokenize(input.source);
    const stream = new TokenStream(tokens);
    const root = this.parseProgram(stream, input.entryFile);
    return {
      version: root.version,
      root,
      source: input.source,
      entryFile: input.entryFile,
    };
  }

  private parseProgram(stream: TokenStream, file: string): ProgramNode {
    let version = "1.0";
    if (stream.match(TokenType.IDENT, "pactia")) {
      const versionToken = stream.expect(TokenType.NUMBER, "Expected pactia version number");
      version = versionToken.value;
    }

    const imports: ImportNode[] = [];
    const exportDefs: DefDeclNode[] = [];
    const fragmentExports: ModuleNode[] = [];
    const fragmentServiceExports: ServiceNode[] = [];
    const fragmentModelExports: ModelNode[] = [];
    const fragmentContextExports: ContextBlockNode[] = [];
    const constantExports: import("../../domain/syntax-tree.js").PackageConstNode[] = [];
    let product: ProductNode | undefined;

    while (!stream.atEnd()) {
      if (stream.match(TokenType.IDENT, "import")) {
        imports.push(this.parseImport(stream, file));
        continue;
      }
      if (stream.match(TokenType.IDENT, "export")) {
        if (stream.check(TokenType.IDENT, "module")) {
          fragmentExports.push(this.parseModule(stream, file));
          continue;
        }
        if (stream.check(TokenType.IDENT, "service")) {
          fragmentServiceExports.push(this.parseService(stream, file));
          continue;
        }
        if (stream.check(TokenType.IDENT, "model")) {
          fragmentModelExports.push(this.parseModel(stream, file));
          continue;
        }
        if (stream.check(TokenType.IDENT, "context")) {
          fragmentContextExports.push(this.parseContextBlock(stream, file, true));
          continue;
        }
        if (this.checkDefStart(stream)) {
          const def = this.parseDefDecl(stream, file, true, true);
          if (def.exported) exportDefs.push(def);
          continue;
        }
        if (this.checkPackageConstStart(stream)) {
          constantExports.push(this.parsePackageConst(stream, file));
          continue;
        }
        // export without def or valid keyword → CONSTANT_DEF_REQUIRED
        if (this.checkBareConstantExport(stream)) {
          constantExports.push(this.parseBareConstantExport(stream, file));
          continue;
        }
        throw new PactiaSyntaxError(
          "Expected export module, export service, export model, export context, or export def",
          stream.peek().line,
          stream.peek().col,
        );
      }
      if (this.checkDefStart(stream)) {
        const def = this.parseDefDecl(stream, file, true);
        if (def.exported) exportDefs.push(def);
        continue;
      }
      if (stream.match(TokenType.IDENT, "product")) {
        product = this.parseProduct(stream, file);
        continue;
      }
      if (stream.check(TokenType.IDENT, "module")) {
        throw new PactiaSyntaxError("module declarations must appear inside product { }", stream.peek().line, stream.peek().col);
      }
      throw new PactiaSyntaxError(`Unexpected token '${stream.peek().value}'`, stream.peek().line, stream.peek().col);
    }

    return {
      kind: SyntaxNodeKind.Workspace,
      version,
      imports,
      exportDefs,
      fragmentExports,
      fragmentServiceExports,
      fragmentModelExports,
      fragmentContextExports,
      constantExports,
      product,
      location: { file, line: 1, col: 1 },
    };
  }

  private parseImport(stream: TokenStream, file: string): ImportNode {
    const symbols: string[] = [];
    if (stream.match(TokenType.LBRACE)) {
      while (!stream.check(TokenType.RBRACE) && !stream.atEnd()) {
        stream.match(TokenType.COMMA);
        if (stream.check(TokenType.RBRACE)) break;
        symbols.push(this.parseImportSymbol(stream));
        stream.match(TokenType.COMMA);
      }
      stream.expect(TokenType.RBRACE, "Expected '}' after import symbol list");
      stream.expect(TokenType.IDENT, "Expected 'from' after import list", "from");
    }

    const pathToken = stream.peek();
    if (pathToken.type !== TokenType.IDENT && pathToken.type !== TokenType.PATH) {
      throw new PactiaSyntaxError("Expected import path", pathToken.line, pathToken.col);
    }
    const path = stream.advance().value;
    stream.match(TokenType.SEMICOLON);
    return {
      kind: SyntaxNodeKind.Import,
      path,
      symbols: symbols.length > 0 ? symbols : undefined,
      location: { file, line: pathToken.line, col: pathToken.col },
    };
  }

  private parseImportSymbol(stream: TokenStream): string {
    if (stream.match(TokenType.HASH, "#")) {
      const name = stream.expect(TokenType.IDENT, "Expected macro name after '#' in import").value;
      return `#${name}`;
    }
    const token = stream.expect(TokenType.IDENT, "Expected import symbol");
    return token.value;
  }

  private parseProduct(stream: TokenStream, file: string): ProductNode {
    const nameToken = stream.expect(TokenType.IDENT, "Expected product name");
    stream.expect(TokenType.LBRACE, "Expected '{' after product name");
    const items: ProductItem[] = [];
    while (!stream.check(TokenType.RBRACE)) {
      stream.match(TokenType.COMMA);
      if (stream.check(TokenType.RBRACE)) break;
      items.push(this.parseProductItem(stream, file));
    }
    stream.expect(TokenType.RBRACE, "Expected '}' to close product block");
    return {
      kind: SyntaxNodeKind.Product,
      name: nameToken.value,
      items,
      location: { file, line: nameToken.line, col: nameToken.col },
    };
  }

  private parseProductItem(stream: TokenStream, file: string): ProductItem {
    if (stream.check(TokenType.IDENT, "module")) {
      if (stream.peek(1).type === TokenType.LPAREN) {
        return this.parseAttachModule(stream, file);
      }
      return this.parseModule(stream, file);
    }
    if (this.checkContextAttachStart(stream)) {
      return this.parseContextAttach(stream, file);
    }
    if (stream.check(TokenType.IDENT, "context")) {
      return this.parseContextBlock(stream, file, false);
    }
    return this.parseTagLikeItem(stream, file) as ProductItem;
  }

  private parseAttachModule(stream: TokenStream, file: string): AttachModuleNode {
    const moduleToken = stream.expect(TokenType.IDENT, "Expected module keyword", "module");
    stream.expect(TokenType.LPAREN, "Expected '(' after module in attach reference");
    const nameToken = stream.expect(TokenType.IDENT, "Expected module attach symbol");
    stream.expect(TokenType.RPAREN, "Expected ')' after module attach symbol");
    stream.expect(TokenType.LBRACE, "Expected '{' after module attach reference");
    const services: AttachServiceNode[] = [];
    while (!stream.check(TokenType.RBRACE)) {
      stream.match(TokenType.COMMA);
      if (stream.check(TokenType.RBRACE)) break;
      services.push(this.parseAttachService(stream, file));
    }
    stream.expect(TokenType.RBRACE, "Expected '}' to close module attach block");
    return {
      kind: SyntaxNodeKind.AttachModule,
      name: nameToken.value,
      services,
      location: { file, line: moduleToken.line, col: moduleToken.col },
    };
  }

  private parseAttachService(stream: TokenStream, file: string): AttachServiceNode {
    const serviceToken = stream.expect(TokenType.IDENT, "Expected service keyword", "service");
    stream.expect(TokenType.LPAREN, "Expected '(' after service in attach reference");
    const nameToken = stream.expect(TokenType.IDENT, "Expected service attach symbol");
    stream.expect(TokenType.RPAREN, "Expected ')' after service attach symbol");
    stream.expect(TokenType.LBRACE, "Expected '{' after service attach reference");
    let modelSymbol: string | undefined;
    const contextSymbols: string[] = [];
    while (!stream.check(TokenType.RBRACE)) {
      stream.match(TokenType.COMMA);
      if (stream.check(TokenType.RBRACE)) break;
      if (stream.match(TokenType.IDENT, "model")) {
        stream.expect(TokenType.LPAREN, "Expected '(' after model in attach reference");
        modelSymbol = stream.expect(TokenType.IDENT, "Expected model attach symbol").value;
        stream.expect(TokenType.RPAREN, "Expected ')' after model attach symbol");
        continue;
      }
      if (this.checkContextAttachStart(stream)) {
        contextSymbols.push(this.parseContextAttach(stream, file).symbol);
        continue;
      }
      throw new PactiaSyntaxError(
        "Attach service blocks may only contain model(...) or context(...) references",
        stream.peek().line,
        stream.peek().col,
      );
    }
    stream.expect(TokenType.RBRACE, "Expected '}' to close service attach block");
    return {
      kind: SyntaxNodeKind.AttachService,
      name: nameToken.value,
      modelSymbol,
      contextSymbols,
      location: { file, line: serviceToken.line, col: serviceToken.col },
    };
  }

  private parseModule(stream: TokenStream, file: string): ModuleNode {
    stream.expect(TokenType.IDENT, "Expected module keyword", "module");
    const nameToken = stream.expect(TokenType.IDENT, "Expected module name");
    stream.expect(TokenType.LBRACE, "Expected '{' after module name");
    const items: ModuleItem[] = [];
    while (!stream.check(TokenType.RBRACE)) {
      stream.match(TokenType.COMMA);
      if (stream.check(TokenType.RBRACE)) break;
      items.push(this.parseModuleItem(stream, file));
    }
    stream.expect(TokenType.RBRACE, "Expected '}' to close module block");
    return {
      kind: SyntaxNodeKind.Module,
      name: nameToken.value,
      items,
      location: { file, line: nameToken.line, col: nameToken.col },
    };
  }

  private parseModuleItem(stream: TokenStream, file: string): ModuleItem {
    if (stream.check(TokenType.IDENT, "service")) return this.parseService(stream, file);
    if (stream.check(TokenType.IDENT, "model")) return this.parseModel(stream, file);
    if (stream.check(TokenType.IDENT, "def")) return this.parseModuleConstOrDef(stream, file);
    if (this.checkContextAttachStart(stream)) return this.parseContextAttach(stream, file);
    if (stream.check(TokenType.IDENT, "context")) return this.parseContextBlock(stream, file, false);
    return this.parseTagLikeItem(stream, file) as ModuleItem;
  }

  private parseModuleConstantDeclaration(stream: TokenStream, file: string): ModuleConstNode | ContextBlockNode {
    stream.expect(TokenType.IDENT, "Expected def keyword", "def");
    const nameToken = stream.expect(TokenType.IDENT, "Expected module constant name");
    stream.expect(TokenType.EQUALS, "Expected '=' in module constant declaration");
    if (stream.check(TokenType.IDENT, "context")) {
      return this.parseContextAlias(stream, file, nameToken.value, {
        file,
        line: nameToken.line,
        col: nameToken.col,
      });
    }
    const valueToken = this.parseModuleConstValue(stream);
    return {
      kind: SyntaxNodeKind.ModuleConst,
      name: nameToken.value,
      value: valueToken,
      location: { file, line: nameToken.line, col: nameToken.col },
    };
  }

  private parseModuleConstOrDef(stream: TokenStream, file: string): ModuleItem {
    if (this.checkDefSigilStart(stream, 0)) {
      return this.parseDefDecl(stream, file, false);
    }
    return this.parseModuleConstantDeclaration(stream, file);
  }

  /** After `export` was consumed: check for `def IDENT =` where IDENT is not a sigil/keyword. */
  private checkPackageConstStart(stream: TokenStream): boolean {
    if (!stream.check(TokenType.IDENT, "def")) return false;
    if (this.checkDefSigilStart(stream, 0)) return false;
    // peek 2 ahead: `def IDENT =`
    const ident = stream.peek(1);
    if (ident.type !== TokenType.IDENT) return false;
    if (this.isBlockKeyword(ident.value)) return false;
    const eq = stream.peek(2);
    return eq.type === TokenType.EQUALS;
  }

  /** After `export` was consumed: check for bare `IDENT =` (missing `def`). */
  private checkBareConstantExport(stream: TokenStream): boolean {
    const ident = stream.peek();
    if (ident.type !== TokenType.IDENT) return false;
    if (this.isBlockKeyword(ident.value)) return false;
    if (ident.value === "def") return false;
    const eq = stream.peek(1);
    return eq.type === TokenType.EQUALS;
  }

  /** Parse `def name = value` at file root after `export` was consumed. */
  private parsePackageConst(stream: TokenStream, file: string): import("../../domain/syntax-tree.js").PackageConstNode {
    stream.expect(TokenType.IDENT, "Expected def keyword", "def");
    const nameToken = stream.expect(TokenType.IDENT, "Expected constant name");
    stream.expect(TokenType.EQUALS, "Expected '=' after constant name");
    const valueToken = this.parseModuleConstValue(stream);
    return {
      kind: SyntaxNodeKind.PackageConst,
      name: nameToken.value,
      value: valueToken,
      hasDef: true,
      location: { file, line: nameToken.line, col: nameToken.col },
    };
  }

  /** Parse bare `name = value` after `export` was consumed (missing `def`).
   *  Parsed as PackageConstNode; CONSTANT_DEF_REQUIRED is emitted in bind pass. */
  private parseBareConstantExport(stream: TokenStream, file: string): import("../../domain/syntax-tree.js").PackageConstNode {
    const nameToken = stream.expect(TokenType.IDENT, "Expected constant name");
    stream.expect(TokenType.EQUALS, "Expected '=' after constant name");
    const valueToken = this.parseModuleConstValue(stream);
    return {
      kind: SyntaxNodeKind.PackageConst,
      name: nameToken.value,
      value: valueToken,
      hasDef: false,
      location: { file, line: nameToken.line, col: nameToken.col },
    };
  }

  private parseContextAlias(
    stream: TokenStream,
    file: string,
    aliasName: string,
    location: { file: string; line: number; col: number },
  ): ContextBlockNode {
    stream.advance();
    const referencedName = stream.expect(TokenType.IDENT, "Expected context name in alias").value;
    stream.expect(TokenType.LBRACE, "Expected '{' after context alias");
    const bodyItems: TagBodyItem[] = [];
    while (!stream.check(TokenType.RBRACE)) {
      bodyItems.push(this.parseContextBodyItem(stream, file));
    }
    stream.expect(TokenType.RBRACE, "Expected '}' to close context alias");
    const pathField = bodyItems.find(
      (item): item is FieldLineNode =>
        item.kind === SyntaxNodeKind.FieldLine && item.name === "path",
    );
    return {
      kind: SyntaxNodeKind.Context,
      name: aliasName,
      exported: false,
      path: pathField?.value,
      pathRaw: pathField?.value,
      guidance: collectContextGuidance(bodyItems),
      location,
    };
  }

  private parseModuleConst(stream: TokenStream, file: string): ModuleConstNode {
    stream.expect(TokenType.IDENT, "Expected def keyword", "def");
    const nameToken = stream.expect(TokenType.IDENT, "Expected module constant name");
    stream.expect(TokenType.EQUALS, "Expected '=' in module constant declaration");
    const valueToken = this.parseModuleConstValue(stream);
    return {
      kind: SyntaxNodeKind.ModuleConst,
      name: nameToken.value,
      value: valueToken,
      location: { file, line: nameToken.line, col: nameToken.col },
    };
  }

  private parseModuleConstValue(stream: TokenStream): string {
    const token = stream.peek();
    if (token.type === TokenType.STRING || token.type === TokenType.NUMBER || token.type === TokenType.IDENT) {
      return stream.advance().value;
    }
    if (token.type === TokenType.GT) {
      return this.parseProse(stream, "").text;
    }
    throw new PactiaSyntaxError("Expected module constant value", token.line, token.col);
  }

  private parseService(stream: TokenStream, file: string): ServiceNode {
    stream.expect(TokenType.IDENT, "Expected service keyword", "service");
    const nameToken = stream.expect(TokenType.IDENT, "Expected service name");
    stream.expect(TokenType.LBRACE, "Expected '{' after service name");
    const items: ServiceItem[] = [];
    while (!stream.check(TokenType.RBRACE)) {
      stream.match(TokenType.COMMA);
      if (stream.check(TokenType.RBRACE)) break;
      if (stream.check(TokenType.IDENT, "def")) {
        items.push(this.parseModuleConstantDeclaration(stream, file));
        continue;
      }
      if (this.checkContextAttachStart(stream)) {
        items.push(this.parseContextAttach(stream, file));
        continue;
      }
      if (stream.check(TokenType.IDENT, "context")) {
        items.push(this.parseContextBlock(stream, file, false));
        continue;
      }
      items.push(this.parseTagLikeItem(stream, file) as ServiceItem);
    }
    stream.expect(TokenType.RBRACE, "Expected '}' to close service block");
    return {
      kind: SyntaxNodeKind.Service,
      name: nameToken.value,
      items,
      location: { file, line: nameToken.line, col: nameToken.col },
    };
  }

  private parseModel(stream: TokenStream, file: string): ModelNode {
    const modelToken = stream.expect(TokenType.IDENT, "Expected model keyword", "model");
    let name: string | undefined;
    if (stream.check(TokenType.IDENT) && stream.peek(1).type === TokenType.LBRACE) {
      name = stream.advance().value;
    }
    stream.expect(TokenType.LBRACE, "Expected '{' after model");
    const items: ModelItem[] = [];
    while (!stream.check(TokenType.RBRACE)) {
      stream.match(TokenType.COMMA);
      if (stream.check(TokenType.RBRACE)) break;
      if (this.checkContextAttachStart(stream)) {
        items.push(this.parseContextAttach(stream, file));
        continue;
      }
      if (stream.check(TokenType.IDENT, "context")) {
        items.push(this.parseContextBlock(stream, file, false));
        continue;
      }
      items.push(this.parseTagLikeItem(stream, file) as ModelItem);
    }
    stream.expect(TokenType.RBRACE, "Expected '}' to close model block");
    return {
      kind: SyntaxNodeKind.Model,
      name,
      items,
      location: { file, line: modelToken.line, col: modelToken.col },
    };
  }

  private parseTagLikeItem(stream: TokenStream, file: string): TagBlockNode | TagPrefixNode | MacroInvocationNode | ProseNode | FieldLineNode {
    stream.match(TokenType.COMMA);
    if (isMacroInvocationStart(stream)) {
      return this.parseMacroInvocation(stream, file);
    }
    if (stream.check(TokenType.IDENT) && isTagToken(stream.peek().value)) {
      return this.parseTagApplication(stream, file);
    }
    if (stream.check(TokenType.GT)) {
      return this.parseProse(stream, file);
    }
    throw new PactiaSyntaxError(`Unexpected token '${stream.peek().value}' in block`, stream.peek().line, stream.peek().col);
  }

  private parseTagApplication(stream: TokenStream, file: string): TagBlockNode | TagPrefixNode {
    const tagToken = stream.expect(TokenType.IDENT, "Expected @tag");
    const modifier = isModifierTagToken(tagToken.value);
    const tagName = tagNameFromToken(tagToken.value);
    let hostId: string | undefined;

    if (
      stream.check(TokenType.IDENT) &&
      !isTagToken(stream.peek().value) &&
      stream.peek(1).type === TokenType.LBRACE
    ) {
      hostId = stream.advance().value;
    }

    if (stream.check(TokenType.LBRACE)) {
      stream.advance();
      const items: TagBodyItem[] = [];
      while (!stream.check(TokenType.RBRACE)) {
        stream.match(TokenType.COMMA);
        if (stream.check(TokenType.RBRACE)) break;
        items.push(this.parseTagBodyItem(stream, file));
      }
      stream.expect(TokenType.RBRACE, "Expected '}' to close tag body");
      return {
        kind: SyntaxNodeKind.TagBlock,
        tagName,
        hostId,
        items,
        location: { file, line: tagToken.line, col: tagToken.col },
      };
    }

    let shorthand: string | undefined;
    if (
      (stream.check(TokenType.IDENT) ||
        stream.check(TokenType.STRING) ||
        stream.check(TokenType.NUMBER)) &&
      stream.peek(1).type !== TokenType.COLON &&
      stream.peek(1).type !== TokenType.LBRACE &&
      (stream.check(TokenType.NUMBER) || !isTagToken(stream.peek().value))
    ) {
      shorthand = stream.advance().value;
    }

    if (stream.check(TokenType.LPAREN)) {
      stream.advance();
      const argToken = stream.expect(TokenType.IDENT, "Expected modifier shorthand argument");
      stream.expect(TokenType.RPAREN, "Expected ')' after modifier shorthand");
      shorthand = argToken.value;
    }

    return {
      kind: SyntaxNodeKind.TagPrefix,
      tagName,
      shorthand,
      modifier,
      location: { file, line: tagToken.line, col: tagToken.col },
    };
  }

  private parseTagBodyItem(stream: TokenStream, file: string): TagBodyItem {
    stream.match(TokenType.COMMA);
    if (isMacroInvocationStart(stream)) {
      return this.parseMacroInvocation(stream, file);
    }
    if (stream.check(TokenType.IDENT) && isTagToken(stream.peek().value)) {
      return this.parseTagApplication(stream, file) as TagBlockNode;
    }
    if (stream.check(TokenType.GT)) {
      return this.parseProse(stream, file);
    }
    return this.parseFieldLine(stream, file);
  }

  private parseFieldLine(stream: TokenStream, file: string): FieldLineNode {
    const nameToken = stream.expect(TokenType.IDENT, "Expected field name");
    if (stream.match(TokenType.COMMA)) {
      return {
        kind: SyntaxNodeKind.FieldLine,
        name: nameToken.value,
        required: true,
        location: { file, line: nameToken.line, col: nameToken.col },
      };
    }
    stream.expect(TokenType.COLON, "Expected ':' or ',' after field name");
    const value = this.parseFieldValue(stream);
    stream.match(TokenType.COMMA);
    return {
      kind: SyntaxNodeKind.FieldLine,
      name: nameToken.value,
      value,
      required: false,
      location: { file, line: nameToken.line, col: nameToken.col },
    };
  }

  private parseFieldValue(stream: TokenStream): string {
    const parts: string[] = [];
    let depth = 0;

    while (!stream.atEnd()) {
      const token = stream.peek();
      if (depth === 0 && token.type === TokenType.COMMA) break;
      if (
        depth === 0 &&
        (token.type === TokenType.RBRACE ||
          (token.type === TokenType.IDENT &&
            (isTagToken(token.value) || this.isBlockKeyword(token.value))))
      ) {
        break;
      }
      if (token.type === TokenType.LBRACKET || token.type === TokenType.LBRACE) depth += 1;
      if (token.type === TokenType.RBRACKET || token.type === TokenType.RBRACE) depth -= 1;
      parts.push(stream.advance().value);
    }

    return parts.join(" ").trim();
  }

  private parseProse(stream: TokenStream, file: string): ProseNode {
    const start = stream.expect(TokenType.GT, "Expected prose prefix '>'");
    if (stream.match(TokenType.GT)) {
      const parts: string[] = [];
      while (!(stream.check(TokenType.GT) && stream.peek(1).type === TokenType.GT)) {
        if (stream.atEnd()) break;
        parts.push(stream.advance().value);
      }
      stream.expect(TokenType.GT, "Expected closing '>>'");
      stream.expect(TokenType.GT, "Expected closing '>>'");
      return {
        kind: SyntaxNodeKind.Prose,
        text: parts.join(" ").trim(),
        multiline: true,
        location: { file, line: start.line, col: start.col },
      };
    }

    const parts: string[] = [];
    while (!stream.atEnd()) {
      const token = stream.peek();
      if (token.line !== start.line) break;
      if (token.type === TokenType.RBRACE) break;
      parts.push(stream.advance().value);
    }

    return {
      kind: SyntaxNodeKind.Prose,
      text: parts.join(" ").trim(),
      multiline: false,
      location: { file, line: start.line, col: start.col },
    };
  }

  private parseMacroInvocation(stream: TokenStream, file: string): MacroInvocationNode {
    stream.expect(TokenType.HASH, "Expected '#'");
    const nameToken = stream.expect(TokenType.IDENT, "Expected macro name");
    const args: string[] = [];
    if (stream.match(TokenType.LPAREN)) {
      while (!stream.check(TokenType.RPAREN) && !stream.atEnd()) {
        args.push(this.parseMacroArg(stream));
        stream.match(TokenType.COMMA);
      }
      stream.expect(TokenType.RPAREN, "Expected ')' after macro args");
    }
    return {
      kind: SyntaxNodeKind.MacroInvocation,
      name: nameToken.value,
      args,
      location: { file, line: nameToken.line, col: nameToken.col },
    };
  }

  private parseMacroArg(stream: TokenStream): string {
    const token = stream.peek();
    if (
      token.type === TokenType.IDENT ||
      token.type === TokenType.STRING ||
      token.type === TokenType.NUMBER
    ) {
      return stream.advance().value;
    }
    throw new PactiaSyntaxError("Expected macro argument", token.line, token.col);
  }

  private parseDefDecl(
    stream: TokenStream,
    file: string,
    atRoot: boolean,
    exportAlreadySeen = false,
  ): DefDeclNode {
    const exported = exportAlreadySeen || stream.match(TokenType.IDENT, "export");
    stream.expect(TokenType.IDENT, "Expected def keyword", "def");

    let sigil: DefSigil;
    let name: string;
    if (stream.match(TokenType.HASH, "#")) {
      sigil = DefSigil.Macro;
      name = stream.expect(TokenType.IDENT, "Expected macro def name").value;
    } else {
      const tagToken = stream.expect(TokenType.IDENT, "Expected @tag def name");
      if (!isTagToken(tagToken.value)) {
        throw new PactiaSyntaxError("Tag defs must use @name sigil", tagToken.line, tagToken.col);
      }
      sigil = DefSigil.Tag;
      name = tagNameFromToken(tagToken.value);
    }

    const params = this.parseOptionalParams(stream);
    const inTargets = this.parseOptionalInClause(stream);
    if (exported && inTargets.length === 0) {
      throw new PactiaSyntaxError("export def must declare in placement targets", stream.peek().line, stream.peek().col);
    }

    stream.expect(TokenType.LBRACE, "Expected '{' to open def body");
    const bodyItems: TagBodyItem[] = [];
    while (!stream.check(TokenType.RBRACE)) {
      bodyItems.push(this.parseTagBodyItem(stream, file));
    }
    stream.expect(TokenType.RBRACE, "Expected '}' to close def body");

    const bodySource = bodyItems
      .map((item) => {
        if (item.kind === SyntaxNodeKind.Prose) return `> ${item.text}`;
        if (item.kind === SyntaxNodeKind.FieldLine) {
          return item.required ? `${item.name},` : `${item.name}: ${item.value ?? ""},`;
        }
        if (item.kind === SyntaxNodeKind.TagBlock) return `@${item.tagName} { ... }`;
        if (item.kind === SyntaxNodeKind.MacroInvocation) {
          const argSuffix = item.args.length > 0 ? `(${item.args.join(", ")})` : "";
          return `#${item.name}${argSuffix}`;
        }
        return "";
      })
      .filter(Boolean)
      .join("\n");

    return {
      kind: exported ? SyntaxNodeKind.DefExport : SyntaxNodeKind.DefLocal,
      exported,
      sigil,
      name,
      params,
      inTargets: inTargets.length > 0 ? inTargets : [...allPlacementTargets],
      modifier: fieldSpecFromDefBody(bodyItems).modifier,
      bodyItems,
      bodySource,
      location: { file, line: stream.location(file).line, col: stream.location(file).col },
    };
  }

  private parseOptionalParams(stream: TokenStream): string[] {
    if (!stream.match(TokenType.LPAREN)) return [];
    const params: string[] = [];
    while (!stream.check(TokenType.RPAREN) && !stream.atEnd()) {
      params.push(stream.expect(TokenType.IDENT, "Expected parameter name").value);
      stream.match(TokenType.COMMA);
    }
    stream.expect(TokenType.RPAREN, "Expected ')' after parameter list");
    return params;
  }

  private parseOptionalInClause(stream: TokenStream): PlacementTarget[] {
    if (!stream.match(TokenType.IDENT, "in")) return [];
    const targets: PlacementTarget[] = [];
    do {
      const targetToken = stream.expect(TokenType.IDENT, "Expected in placement target");
      const parsed = parsePlacementTarget(targetToken.value);
      if (!parsed) {
        throw new PactiaSyntaxError(`Unknown placement target '${targetToken.value}'`, targetToken.line, targetToken.col);
      }
      targets.push(parsed);
      if (!stream.match(TokenType.COMMA)) break;
    } while (!stream.check(TokenType.LBRACE));
    return targets;
  }

  private checkDefStart(stream: TokenStream): boolean {
    if (stream.check(TokenType.IDENT, "export") && stream.peek(1).type === TokenType.IDENT && stream.peek(1).value === "def") {
      return true;
    }
    return stream.check(TokenType.IDENT, "def") && this.checkDefSigilStart(stream, 0);
  }

  private checkDefSigilStart(stream: TokenStream, defOffset: number): boolean {
    const next = stream.peek(defOffset + 1);
    if (next.type === TokenType.HASH) return true;
    return next.type === TokenType.IDENT && isTagToken(next.value);
  }

  private isBlockKeyword(value: string): boolean {
    return value === "module" || value === "service" || value === "model" || value === "def" || value === "context";
  }

  private checkContextAttachStart(stream: TokenStream): boolean {
    return stream.check(TokenType.IDENT, "context") && stream.peek(1).type === TokenType.LPAREN;
  }

  private parseContextAttach(stream: TokenStream, file: string): ContextAttachNode {
    const contextToken = stream.expect(TokenType.IDENT, "Expected context keyword", "context");
    stream.expect(TokenType.LPAREN, "Expected '(' after context attach");
    const symbol = stream.expect(TokenType.IDENT, "Expected context attach symbol").value;
    stream.expect(TokenType.RPAREN, "Expected ')' after context attach symbol");
    stream.match(TokenType.COMMA);
    return {
      kind: SyntaxNodeKind.ContextAttach,
      symbol,
      location: { file, line: contextToken.line, col: contextToken.col },
    };
  }

  private parseContextBlock(stream: TokenStream, file: string, exported: boolean): ContextBlockNode {
    const contextToken = stream.expect(TokenType.IDENT, "Expected context keyword", "context");
    const nameToken = stream.expect(TokenType.IDENT, "Expected context name");
    stream.expect(TokenType.LBRACE, "Expected '{' after context name");
    const bodyItems: TagBodyItem[] = [];
    while (!stream.check(TokenType.RBRACE)) {
      bodyItems.push(this.parseContextBodyItem(stream, file));
    }
    stream.expect(TokenType.RBRACE, "Expected '}' to close context block");
    const pathField = bodyItems.find(
      (item): item is FieldLineNode =>
        item.kind === SyntaxNodeKind.FieldLine && item.name === "path",
    );
    return {
      kind: SyntaxNodeKind.Context,
      name: nameToken.value,
      exported,
      path: pathField?.value,
      pathRaw: pathField?.value,
      guidance: collectContextGuidance(bodyItems),
      location: { file, line: contextToken.line, col: contextToken.col },
    };
  }

  private parseContextBodyItem(stream: TokenStream, file: string): TagBodyItem {
    stream.match(TokenType.COMMA);
    if (stream.check(TokenType.GT)) {
      return this.parseProse(stream, file);
    }
    if (stream.check(TokenType.IDENT, "path")) {
      return this.parseFieldLine(stream, file);
    }
    throw new PactiaSyntaxError(
      "Context blocks may only contain path and prose",
      stream.peek().line,
      stream.peek().col,
    );
  }
}

export const recursiveDescentParser = new RecursiveDescentParser();

export function parseSyntaxTree(input: ParseInput): SyntaxTree {
  return recursiveDescentParser.parse(input);
}

/** Registry `in` placement targets — spec/docs/registry.md. */
export enum PlacementTarget {
  Product = "product",
  Module = "module",
  Model = "model",
  Service = "service",
  Field = "field",
}

export const placementTargetValues: readonly PlacementTarget[] = Object.values(
  PlacementTarget,
) as PlacementTarget[];

/** All placement targets — used when local `def` omits `in`. */
export const allPlacementTargets: readonly PlacementTarget[] = placementTargetValues;

export function placementAllows(
  allowed: readonly PlacementTarget[],
  site: PlacementTarget,
): boolean {
  return allowed.includes(site);
}

export function parsePlacementTarget(value: string): PlacementTarget | undefined {
  return placementTargetValues.find((target) => target === value);
}

import { SyntaxNodeKind, type TagBodyItem } from "./syntax-tree.js";

export function stripQuotedPath(value: string): string {
  const trimmed = value.trim();
  if (
    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
    (trimmed.startsWith("'") && trimmed.endsWith("'"))
  ) {
    return trimmed.slice(1, -1);
  }
  return trimmed;
}

/** Parse a context `path:` field value into a file path or explicit file group. */
export function parseContextPathField(raw: string | undefined): string | readonly string[] | undefined {
  if (raw === undefined || raw.length === 0) return undefined;
  const trimmed = raw.trim();
  if (trimmed.startsWith("[")) {
    const close = trimmed.lastIndexOf("]");
    const inner = close > 0 ? trimmed.slice(1, close) : trimmed.slice(1);
    return inner
      .split(",")
      .map((part) => stripQuotedPath(part))
      .filter((part) => part.length > 0);
  }
  return stripQuotedPath(trimmed);
}

export function collectContextGuidance(items: readonly TagBodyItem[]): string[] {
  const guidance: string[] = [];
  for (const item of items) {
    if (item.kind === SyntaxNodeKind.Prose && item.text.length > 0) {
      guidance.push(item.text);
    }
  }
  return guidance;
}

export enum TokenType {
  IDENT = "IDENT",
  STRING = "STRING",
  NUMBER = "NUMBER",
  PATH = "PATH",
  ARROW = "ARROW",
  LBRACE = "LBRACE",
  RBRACE = "RBRACE",
  LBRACKET = "LBRACKET",
  RBRACKET = "RBRACKET",
  COMMA = "COMMA",
  COLON = "COLON",
  QUESTION = "QUESTION",
  CARET = "CARET",
  STAR = "STAR",
  HASH = "HASH",
  GT = "GT",
  LT = "LT",
  LPAREN = "LPAREN",
  RPAREN = "RPAREN",
  SEMICOLON = "SEMICOLON",
  EQUALS = "EQUALS",
  EOF = "EOF",
}

export interface Token {
  readonly type: TokenType;
  readonly value: string;
  readonly line: number;
  readonly col: number;
}

export class PactiaSyntaxError extends Error {
  constructor(
    message: string,
    public readonly line: number,
    public readonly col: number,
  ) {
    super(`${message} (line ${line}, col ${col})`);
    this.name = "PactiaSyntaxError";
  }
}

const SINGLE_CHAR_TOKENS: Readonly<Record<string, TokenType>> = {
  "{": TokenType.LBRACE,
  "}": TokenType.RBRACE,
  "[": TokenType.LBRACKET,
  "]": TokenType.RBRACKET,
  ",": TokenType.COMMA,
  ":": TokenType.COLON,
  "?": TokenType.QUESTION,
  "^": TokenType.CARET,
  "*": TokenType.STAR,
  "#": TokenType.HASH,
  ">": TokenType.GT,
  "<": TokenType.LT,
  "(": TokenType.LPAREN,
  ")": TokenType.RPAREN,
  ";": TokenType.SEMICOLON,
  "=": TokenType.EQUALS,
};

function isIdentStart(ch: string): boolean {
  return /[A-Za-z_]/.test(ch);
}

function isIdentPart(ch: string): boolean {
  return /[A-Za-z0-9_.\-]/.test(ch);
}

function isDigit(ch: string): boolean {
  return ch >= "0" && ch <= "9";
}

function isPathPart(ch: string): boolean {
  return /[A-Za-z0-9_/:{}.\-]/.test(ch);
}

/**
 * Deterministic, dependency-free tokenizer for the Pactia kernel subset.
 * No lookahead heuristics beyond a fixed two-character arrow; every byte maps
 * to exactly one token so the same source always produces the same tokens.
 */
export function tokenize(source: string): Token[] {
  const tokens: Token[] = [];
  let i = 0;
  let line = 1;
  let col = 1;

  const advance = (): string => {
    const ch = source[i] ?? "";
    i += 1;
    if (ch === "\n") {
      line += 1;
      col = 1;
    } else {
      col += 1;
    }
    return ch;
  };

  while (i < source.length) {
    const startLine = line;
    const startCol = col;
    const ch = source[i] ?? "";

    if (ch === " " || ch === "\t" || ch === "\r" || ch === "\n") {
      advance();
      continue;
    }

    // Block comments: /* ... */
    if (ch === "/" && source[i + 1] === "*") {
      advance();
      advance();
      while (
        i < source.length &&
        !(source[i] === "*" && source[i + 1] === "/")
      ) {
        advance();
      }
      if (i < source.length) {
        advance();
        advance();
      }
      continue;
    }

    // Line comments: //
    if (ch === "/" && source[i + 1] === "/") {
      while (i < source.length && source[i] !== "\n") advance();
      continue;
    }

    // String literal
    if (ch === '"') {
      advance();
      let value = "";
      while (i < source.length && source[i] !== '"') {
        if (source[i] === "\n") {
          throw new PactiaSyntaxError(
            "Unterminated string literal",
            startLine,
            startCol,
          );
        }
        value += advance();
      }
      if (i >= source.length) {
        throw new PactiaSyntaxError(
          "Unterminated string literal",
          startLine,
          startCol,
        );
      }
      advance(); // closing quote
      tokens.push({
        type: TokenType.STRING,
        value,
        line: startLine,
        col: startCol,
      });
      continue;
    }

    // Package coordinate: @scope/name (emitted as a single IDENT token)
    if (ch === "@") {
      let value = "";
      while (i < source.length && /[A-Za-z0-9_/.@-]/.test(source[i] ?? ""))
        value += advance();
      tokens.push({
        type: TokenType.IDENT,
        value,
        line: startLine,
        col: startCol,
      });
      continue;
    }

    // Arrow: ->
    if (ch === "-" && source[i + 1] === ">") {
      advance();
      advance();
      tokens.push({
        type: TokenType.ARROW,
        value: "->",
        line: startLine,
        col: startCol,
      });
      continue;
    }

    // Relative path: ./foo or ../foo
    if (ch === "." && (source[i + 1] === "/" || source[i + 1] === ".")) {
      let value = "";
      while (i < source.length && isPathPart(source[i] ?? ""))
        value += advance();
      tokens.push({
        type: TokenType.PATH,
        value,
        line: startLine,
        col: startCol,
      });
      continue;
    }

    // Constant interpolation in prose: ${name}
    if (ch === "$" && source[i + 1] === "{") {
      let value = advance();
      value += advance();
      while (i < source.length && isIdentPart(source[i] ?? "")) {
        value += advance();
      }
      if (source[i] !== "}") {
        throw new PactiaSyntaxError(
          "Unterminated constant interpolation",
          startLine,
          startCol,
        );
      }
      value += advance();
      tokens.push({
        type: TokenType.IDENT,
        value,
        line: startLine,
        col: startCol,
      });
      continue;
    }

    // Path: starts with '/'
    if (ch === "/") {
      let value = "";
      while (i < source.length && isPathPart(source[i] ?? ""))
        value += advance();
      tokens.push({
        type: TokenType.PATH,
        value,
        line: startLine,
        col: startCol,
      });
      continue;
    }

    // Number (used for version constraints like 1.0)
    if (isDigit(ch)) {
      let value = "";
      while (i < source.length && /[0-9.%]/.test(source[i] ?? ""))
        value += advance();
      tokens.push({
        type: TokenType.NUMBER,
        value,
        line: startLine,
        col: startCol,
      });
      continue;
    }

    // Identifier / keyword. Hyphens are allowed inside identifiers (e.g. the
    // stack id `rust-stack`, header `X-Device-Api-Key`) but never when they begin
    // the `->` arrow, which is matched earlier.
    if (isIdentStart(ch)) {
      let value = "";
      while (i < source.length) {
        const next = source[i] ?? "";
        if (next === "-" && source[i + 1] === ">") break;
        if (!isIdentPart(next)) break;
        value += advance();
      }
      tokens.push({
        type: TokenType.IDENT,
        value,
        line: startLine,
        col: startCol,
      });
      continue;
    }

    const single = SINGLE_CHAR_TOKENS[ch];
    if (single !== undefined) {
      advance();
      tokens.push({ type: single, value: ch, line: startLine, col: startCol });
      continue;
    }

    // Unicode punctuation common in prose lines.
    if (ch === "→" || ch === "—" || ch === "…") {
      tokens.push({
        type: TokenType.IDENT,
        value: advance(),
        line: startLine,
        col: startCol,
      });
      continue;
    }

    throw new PactiaSyntaxError(
      `Unexpected character '${ch}'`,
      startLine,
      startCol,
    );
  }

  tokens.push({ type: TokenType.EOF, value: "", line, col });
  return tokens;
}

import { PactiaSyntaxError, type Token, TokenType } from "../../frontend/lexer/tokens.js";

export class TokenStream {
  private index = 0;

  constructor(private readonly tokens: readonly Token[]) {}

  peek(offset = 0): Token {
    return this.tokens[this.index + offset] ?? this.tokens[this.tokens.length - 1]!;
  }

  advance(): Token {
    const token = this.peek();
    if (token.type !== TokenType.EOF) this.index += 1;
    return token;
  }

  atEnd(): boolean {
    return this.peek().type === TokenType.EOF;
  }

  match(type: TokenType, value?: string): boolean {
    const token = this.peek();
    if (token.type !== type) return false;
    if (value !== undefined && token.value !== value) return false;
    this.advance();
    return true;
  }

  expect(type: TokenType, message: string, value?: string): Token {
    const token = this.peek();
    if (token.type !== type || (value !== undefined && token.value !== value)) {
      throw new PactiaSyntaxError(message, token.line, token.col);
    }
    return this.advance();
  }

  check(type: TokenType, value?: string): boolean {
    const token = this.peek();
    if (token.type !== type) return false;
    if (value !== undefined && token.value !== value) return false;
    return true;
  }

  location(file: string): { readonly file: string; readonly line: number; readonly col: number } {
    const token = this.peek();
    return { file, line: token.line, col: token.col };
  }
}

export function isModifierTagToken(value: string): boolean {
  return value.startsWith("@@");
}

export function isTagToken(value: string): boolean {
  return value.startsWith("@") && !value.includes("/");
}

export function tagNameFromToken(value: string): string {
  if (isModifierTagToken(value)) return value.slice(2);
  return value.startsWith("@") ? value.slice(1) : value;
}

export function isMacroInvocationStart(stream: TokenStream): boolean {
  if (!stream.check(TokenType.HASH, "#")) return false;
  const next = stream.peek(1);
  return next.type === TokenType.IDENT;
}

import {
  RegistryEntryKind,
  type DefBodyAst,
  type EffectiveRegistry,
  type PackageContextExport,
  type RegistryMacroEntry,
  type RegistryTagEntry,
} from "../../domain/registry.js";
import type { DefDeclNode, ProgramNode, ContextBlockNode } from "../../domain/syntax-tree.js";
import { DefSigil as DefSigilEnum } from "../../domain/syntax-tree.js";
import { fieldSpecFromDefBody } from "../parse/recursive-descent-parser.js";
import { deriveIrSlotForTag } from "./derive-tag-ir.js";

function defBodyFromDecl(def: DefDeclNode): DefBodyAst {
  return {
    lines: def.bodySource.split("\n").filter((line) => line.length > 0),
    items: def.bodyItems,
  };
}

function defToRegistryEntries(
  def: DefDeclNode,
  source: string,
): RegistryTagEntry | RegistryMacroEntry | undefined {
  const body = defBodyFromDecl(def);

  if (def.sigil === DefSigilEnum.Macro) {
    return {
      kind: RegistryEntryKind.Macro,
      name: def.name,
      source,
      in: def.inTargets,
      params: def.params,
      body,
    };
  }

  const ir = deriveIrSlotForTag(def);

  return {
    kind: RegistryEntryKind.Tag,
    name: def.name,
    source,
    in: def.inTargets,
    fields: fieldSpecFromDefBody(def.bodyItems),
    modifier: def.modifier,
    ir,
  };
}

export function registryEntriesFromProgram(
  program: ProgramNode,
  source: string,
): { readonly tags: RegistryTagEntry[]; readonly macros: RegistryMacroEntry[] } {
  const tags: RegistryTagEntry[] = [];
  const macros: RegistryMacroEntry[] = [];

  for (const def of program.exportDefs) {
    const entry = defToRegistryEntries(def, source);
    if (!entry) continue;
    if (entry.kind === RegistryEntryKind.Tag) tags.push(entry);
    else macros.push(entry);
  }

  return { tags, macros };
}

export function constantsFromProgram(
  program: ProgramNode,
): readonly { readonly name: string; readonly value: string }[] {
  return program.constantExports.map((c) => ({
    name: c.name,
    value: c.value,
  }));
}

export function contextExportsFromProgram(
  program: ProgramNode,
  coordinate: string,
): readonly PackageContextExport[] {
  return program.fragmentContextExports.map((ctx) => ({
    name: ctx.name,
    coordinate,
    pathRaw: ctx.pathRaw,
    guidance: ctx.guidance,
  }));
}

export function filterContextExports(
  exports: readonly PackageContextExport[],
  partialSymbols: readonly string[] | undefined,
): PackageContextExport[] {
  if (!partialSymbols || partialSymbols.length === 0) {
    return [...exports];
  }
  const allowed = new Set(
    partialSymbols
      .filter((symbol) => !symbol.startsWith("@") && !symbol.startsWith("#"))
      .map((symbol) => symbol.trim()),
  );
  return exports.filter((entry) => allowed.has(entry.name));
}

export function registryEntriesFromLocalDefs(
  defs: readonly DefDeclNode[],
  source: string,
): { readonly tags: RegistryTagEntry[]; readonly macros: RegistryMacroEntry[] } {
  const tags: RegistryTagEntry[] = [];
  const macros: RegistryMacroEntry[] = [];

  for (const def of defs) {
    if (def.exported) continue;
    const body = defBodyFromDecl(def);
    if (def.sigil === DefSigilEnum.Macro) {
      macros.push({
        kind: RegistryEntryKind.Macro,
        name: def.name,
        source,
        in: def.inTargets,
        params: def.params,
        body,
      });
      continue;
    }
    tags.push({
      kind: RegistryEntryKind.Tag,
      name: def.name,
      source,
      in: def.inTargets,
      fields: fieldSpecFromDefBody(def.bodyItems),
      modifier: def.modifier,
      ir: deriveIrSlotForTag(def),
    });
  }

  return { tags, macros };
}

export interface MergeRegistryInput {
  readonly importEntries: ReadonlyArray<{
    readonly coordinate: string;
    readonly tier: import("../../domain/registry.js").RegistryPrecedenceTier;
    readonly tags: readonly RegistryTagEntry[];
    readonly macros: readonly RegistryMacroEntry[];
    readonly contexts: readonly PackageContextExport[];
    readonly constants: ReadonlyMap<string, string>;
  }>;
  readonly localTags: readonly RegistryTagEntry[];
  readonly localMacros: readonly RegistryMacroEntry[];
}

export function mergeEffectiveRegistry(input: MergeRegistryInput): EffectiveRegistry {
  const tags = new Map<string, RegistryTagEntry>();
  const macros = new Map<string, RegistryMacroEntry>();
  const contexts = new Map<string, PackageContextExport>();
  const constants = new Map<string, string>();

  const registerTag = (entry: RegistryTagEntry, tierLabel: string): void => {
    const existing = tags.get(entry.name);
    if (existing && existing.source !== entry.source) {
      throw new Error(
        `REGISTRY_COLLISION: '${entry.name}' exported by both '${existing.source}' and '${entry.source}' (${tierLabel})`,
      );
    }
    tags.set(entry.name, entry);
  };

  const registerMacro = (entry: RegistryMacroEntry, tierLabel: string): void => {
    const existing = macros.get(entry.name);
    if (existing && existing.source !== entry.source) {
      throw new Error(
        `REGISTRY_COLLISION: '${entry.name}' exported by both '${existing.source}' and '${entry.source}' (${tierLabel})`,
      );
    }
    macros.set(entry.name, entry);
  };

  const registerContext = (entry: PackageContextExport): void => {
    const existing = contexts.get(entry.name);
    if (existing && existing.coordinate !== entry.coordinate) {
      throw new Error(
        `REGISTRY_COLLISION: context '${entry.name}' exported by both '${existing.coordinate}' and '${entry.coordinate}'`,
      );
    }
    contexts.set(entry.name, entry);
  };

  for (const pkg of input.importEntries) {
    for (const tag of pkg.tags) registerTag(tag, pkg.coordinate);
    for (const macro of pkg.macros) registerMacro(macro, pkg.coordinate);
    for (const contextExport of pkg.contexts) registerContext(contextExport);
    for (const [name, value] of pkg.constants) {
      const existing = constants.get(name);
      if (existing !== undefined && existing !== value) {
        throw new Error(
          `REGISTRY_COLLISION: constant '${name}' exported with conflicting values '${existing}' and '${value}'`,
        );
      }
      constants.set(name, value);
    }
  }

  for (const tag of input.localTags) registerTag(tag, "local");
  for (const macro of input.localMacros) registerMacro(macro, "local");

  return { tags, macros, contexts, constants };
}

import { IrBodySlot } from "../../domain/ir-body.js";
import { IrFile, irFileForPlacement } from "../../domain/ir-file.js";
import { IrMerge } from "../../domain/ir-merge.js";
import { PlacementTarget } from "../../domain/placement.js";
import type { IrSlot } from "../../domain/registry.js";
import type { DefDeclNode } from "../../domain/syntax-tree.js";
import { kernelTagIrMerge } from "./kernel-tag-ir-paths.js";

function defaultPathForPlacement(placement: PlacementTarget, modifier: boolean): string {
  if (placement === PlacementTarget.Field) return "fields[]";
  if (modifier) return "modifiers";
  return IrBodySlot.BodyArray;
}

function defaultMergeForDef(def: DefDeclNode): IrMerge {
  if (def.modifier) return IrMerge.MergeIntoHost;
  if (def.inTargets.includes(PlacementTarget.Field)) return IrMerge.FieldAnnotation;
  return IrMerge.AppendHost;
}

/** Derive IR slot from export def — one ordered `body[]` per scope; merge hints from kernel table. */
export function deriveIrSlotForTag(def: DefDeclNode): IrSlot {
  const primaryIn = def.inTargets[0] ?? PlacementTarget.Service;
  const file = irFileForPlacement(primaryIn) ?? IrFile.Service;
  const kernelRule = kernelTagIrMerge(def.name);
  return {
    file,
    path: defaultPathForPlacement(primaryIn, def.modifier),
    merge: kernelRule?.merge ?? defaultMergeForDef(def),
  };
}

/** Ordered lowering stream within each IR slice — preserves source sequence. */
export enum IrBodySlot {
  BodyArray = "body[]",
}

/** Structural context attachments on each IR slice (language keyword — not registry tags). */
export enum IrContextSlot {
  ContextArray = "context",
}

/** Language-level `body[]` entry kinds — not registry `@tag` symbols. */
export enum IrBodyKind {
  Prose = "prose",
}

import { PlacementTarget } from "./placement.js";

/** IR file kind selected by enclosing Pactia block scope. */
export enum IrFile {
  Product = "product",
  Module = "module",
  Model = "model",
  Service = "service",
}

export const irFileValues: readonly IrFile[] = Object.values(IrFile) as IrFile[];

export function parseIrFile(value: string): IrFile | undefined {
  return irFileValues.find((file) => file === value);
}

/** Map enclosing block placement to the IR file that receives lowered tags. */
export function irFileForPlacement(placement: PlacementTarget): IrFile | undefined {
  switch (placement) {
    case PlacementTarget.Product:
      return IrFile.Product;
    case PlacementTarget.Module:
      return IrFile.Module;
    case PlacementTarget.Model:
    case PlacementTarget.Field:
      return IrFile.Model;
    case PlacementTarget.Service:
      return IrFile.Service;
    default: {
      const _exhaustive: never = placement;
      return _exhaustive;
    }
  }
}

import { IrMerge } from "../../domain/ir-merge.js";

/** Optional merge override per kernel tag name — path is always {@link IrBodySlot.BodyArray}. */
export interface KernelTagIrMergeRule {
  readonly merge: IrMerge;
}

/**
 * Kernel tag merge hints (@pactia/kernel).
 * Container path is always `body[]` (source order); see spec/docs/compilation.md.
 */
export const KERNEL_TAG_IR_MERGE: Readonly<Record<string, KernelTagIrMergeRule>> = {
  output: { merge: IrMerge.MergeIntoHost },
  input: { merge: IrMerge.MergeIntoHost },
  throws: { merge: IrMerge.MergeIntoHost },
  public: { merge: IrMerge.MergeIntoHost },
  pk: { merge: IrMerge.FieldAnnotation },
  nullable: { merge: IrMerge.FieldAnnotation },
  unique: { merge: IrMerge.FieldAnnotation },
  pii: { merge: IrMerge.FieldAnnotation },
};

export function kernelTagIrMerge(tagName: string): KernelTagIrMergeRule | undefined {
  return KERNEL_TAG_IR_MERGE[tagName];
}

/** Parsed import list entry per spec/docs/grammar-reference.md ImportSymbol. */
export enum ImportSymbolKind {
  Tag = "tag",
  ModifierTag = "modifier-tag",
  Macro = "macro",
  Constant = "constant",
}

export interface ParsedImportSymbol {
  readonly kind: ImportSymbolKind;
  readonly name: string;
  readonly raw: string;
}

export function parseImportSymbol(raw: string): ParsedImportSymbol {
  if (raw.startsWith("@@")) {
    return { kind: ImportSymbolKind.ModifierTag, name: raw.slice(2), raw };
  }
  if (raw.startsWith("@")) {
    return { kind: ImportSymbolKind.Tag, name: raw.slice(1), raw };
  }
  if (raw.startsWith("#")) {
    return { kind: ImportSymbolKind.Macro, name: raw.slice(1), raw };
  }
  return { kind: ImportSymbolKind.Constant, name: raw, raw };
}

export interface PartialImportFilter {
  readonly tagNames: ReadonlySet<string>;
  readonly macroNames: ReadonlySet<string>;
}

export function partialImportFilterFromSymbols(symbols: readonly string[]): PartialImportFilter {
  const tagNames = new Set<string>();
  const macroNames = new Set<string>();
  for (const raw of symbols) {
    const parsed = parseImportSymbol(raw);
    if (parsed.kind === ImportSymbolKind.Tag || parsed.kind === ImportSymbolKind.ModifierTag) {
      tagNames.add(parsed.name);
    } else if (parsed.kind === ImportSymbolKind.Macro) {
      macroNames.add(parsed.name);
    }
  }
  return { tagNames, macroNames };
}

export function applyPartialImportFilter<
  TTag extends { readonly name: string },
  TMacro extends { readonly name: string },
>(
  tags: readonly TTag[],
  macros: readonly TMacro[],
  symbols: readonly string[] | undefined,
): { readonly tags: TTag[]; readonly macros: TMacro[] } {
  if (!symbols || symbols.length === 0) {
    return { tags: [...tags], macros: [...macros] };
  }

  const filter = partialImportFilterFromSymbols(symbols);
  const hasTagFilter = filter.tagNames.size > 0;
  const hasMacroFilter = filter.macroNames.size > 0;

  return {
    tags: hasTagFilter ? tags.filter((tag) => filter.tagNames.has(tag.name)) : [],
    macros: hasMacroFilter ? macros.filter((macro) => filter.macroNames.has(macro.name)) : [],
  };
}

import { readFileSync, existsSync } from "node:fs";
import { join } from "node:path";
import type { LockReaderSync, PactiaLockfile } from "../ports/lock-reader.js";
import { parsePactiaLockToml } from "../resolve/toml-lock.js";

export class TomlLockReader implements LockReaderSync {
  read(input: { readonly workspaceRoot: string }): PactiaLockfile | undefined {
    const lockPath = join(input.workspaceRoot, "pactia.lock");
    if (!existsSync(lockPath)) return undefined;
    return parsePactiaLockToml(readFileSync(lockPath, "utf8"));
  }
}

export function readPactiaLock(source: string): PactiaLockfile {
  return parsePactiaLockToml(source);
}

import { compilePhaseOrder, CompilePhase } from "../domain/compile-phase.js";
import { DiagnosticCode, createDiagnostic, hasErrors } from "../domain/index.js";
import { detectPactiaVersion } from "../compile/version.js";
import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";
import { lockfileDigest } from "../resolve/manifest.js";
import { bindSyntaxTree } from "../passes/bind/bind-syntax-tree.js";
import { expandBoundTree } from "../passes/expand-macros/expand-bound-tree.js";
import { validateBoundTree } from "../passes/validate/index.js";
import { lowerBoundTree } from "../passes/lower/lower-bound-tree.js";

import {
  applyConstantSubstitution,
  importedConstantsFromProgram,
} from "../passes/parse/apply-constant-substitution.js";
import { collectImportUnusedDiagnostics } from "../passes/workspace/workspace-diagnostics.js";
import type {
  CompileContext,
  CompilePipelineOptions,
  CompilePipelineResult,
} from "./compile-context.js";

function assertSupportedVersion(source: string): readonly ReturnType<typeof createDiagnostic>[] {
  const version = detectPactiaVersion(source);
  if (version !== "1.0" && !version.startsWith("1.0.")) {
    return [
      createDiagnostic(
        DiagnosticCode.UnsupportedVersion,
        `Unsupported pactia version: ${version}. Expected pactia 1.0`,
      ),
    ];
  }
  return [];
}

/**
 * v2 compile orchestrator — wires phases 0–12 per spec/docs/compilation.md.
 */
export class CompilePipeline {
  constructor(private readonly options: CompilePipelineOptions) {}

  static readonly phases = compilePhaseOrder;

  run(context: CompileContext): CompilePipelineResult {
    const stopAfter = this.options.stopAfterPhase ?? CompilePhase.Emit;
    const diagnostics: ReturnType<typeof createDiagnostic>[] = [];
    const emptyRegistry: CompilePipelineResult["registry"] = {
      tags: new Map(),
      macros: new Map(),
      contexts: new Map(),
      constants: new Map(),
    };

    diagnostics.push(...assertSupportedVersion(context.source));
    if (diagnostics.length > 0) {
      return { files: new Map(), diagnostics, provenanceGaps: [], registry: emptyRegistry };
    }

    if (stopAfter < CompilePhase.Parse) {
      return { files: new Map(), diagnostics, provenanceGaps: [], registry: emptyRegistry };
    }

    let syntax: CompilePipelineResult["syntax"];
    try {
      syntax = this.options.ports.parser.parse({
        source: context.source,
        entryFile: context.entryFile,
      });
    } catch (error) {
      diagnostics.push(
        createDiagnostic(
          DiagnosticCode.ParseError,
          error instanceof Error ? error.message : "Parse failed",
        ),
      );
      return { files: new Map(), diagnostics, provenanceGaps: [], registry: emptyRegistry };
    }

    diagnostics.push(...collectImportUnusedDiagnostics(context.source, context.entryFile));

    const importConstants = importedConstantsFromProgram(syntax.root, context.workspaceRoot);
    const substituted = applyConstantSubstitution(syntax, importConstants);
    syntax = substituted.tree;
    diagnostics.push(...substituted.diagnostics);

    if (stopAfter < CompilePhase.ResolvePackages) {
      return { files: new Map(), diagnostics, provenanceGaps: [], registry: emptyRegistry, syntax };
    }

    const imports = syntax.root.imports
      .map((node) => node.path)
      .filter((path) => path.startsWith("@"));

    let registry = emptyRegistry;
    const partialImports = new Map<string, readonly string[]>();
    for (const node of syntax.root.imports) {
      if (node.path.startsWith("@") && node.symbols && node.symbols.length > 0) {
        partialImports.set(node.path, node.symbols);
      }
    }
    let expansionRegistry = emptyRegistry;
    try {
      registry = this.options.ports.registryLoader.load({
        workspaceRoot: context.workspaceRoot,
        importCoordinates: imports,
        syntax,
        partialImports,
      });
      expansionRegistry = this.options.ports.registryLoader.load({
        workspaceRoot: context.workspaceRoot,
        importCoordinates: imports,
        syntax,
        partialImports,
        macroExpansion: true,
      });
    } catch (error) {
      diagnostics.push(
        createDiagnostic(
          DiagnosticCode.PackageNotFound,
          error instanceof Error ? error.message : "Package resolution failed",
        ),
      );
      return { files: new Map(), diagnostics, provenanceGaps: [], registry: emptyRegistry, syntax };
    }

    if (stopAfter < CompilePhase.Bind) {
      return { files: new Map(), diagnostics, provenanceGaps: [], registry, syntax };
    }

    const bindResult = bindSyntaxTree(syntax, registry);
    diagnostics.push(...bindResult.diagnostics);

    if (stopAfter <= CompilePhase.Bind) {
      return {
        files: new Map(),
        diagnostics,
        provenanceGaps: [],
        registry,
        syntax,
        bound: bindResult.tree,
      };
    }

    const expandResult = expandBoundTree(bindResult.tree, registry, expansionRegistry);
    diagnostics.push(...expandResult.diagnostics);
    const bound = expandResult.tree;

    if (stopAfter <= CompilePhase.ExpandMacros) {
      return {
        files: new Map(),
        diagnostics,
        provenanceGaps: [],
        registry,
        syntax,
        bound,
      };
    }

    const validateResult = validateBoundTree(bound);
    diagnostics.push(...validateResult.diagnostics);

    const lockPath = join(context.workspaceRoot, "pactia.lock");
    const lockSource = existsSync(lockPath) ? readFileSync(lockPath, "utf8") : undefined;

    const lowerResult = lowerBoundTree({
      tree: bound,
      pactiaVersion: syntax.version,
      entryFile: context.entryFile,
      lockfileDigest: lockSource ? lockfileDigest(lockSource) : undefined,
    });
    diagnostics.push(...lowerResult.diagnostics);

    const lowered = {
      workspace: lowerResult.workspace,
      files: lowerResult.files,
    };

    if (hasErrors(diagnostics)) {
      return {
        files: new Map(),
        diagnostics,
        provenanceGaps: [],
        registry,
        syntax,
        bound,
        lowered,
      };
    }

    if (stopAfter <= CompilePhase.Lower) {
      return {
        files: lowerResult.files,
        diagnostics,
        provenanceGaps: [],
        registry,
        syntax,
        bound,
        lowered,
      };
    }

    this.options.ports.irEmitter.emit({ workspace: lowered, outputRoot: context.workspaceRoot });

    if (stopAfter <= CompilePhase.Emit) {
      return {
        files: lowerResult.files,
        diagnostics,
        provenanceGaps: [],
        registry,
        syntax,
        bound,
        lowered,
      };
    }

    diagnostics.push(
      createDiagnostic(
        DiagnosticCode.ParseError,
        `pactiac v2 pipeline not yet wired through phase ${stopAfter}`,
      ),
    );
    return { files: lowerResult.files, diagnostics, provenanceGaps: [], registry, syntax, bound, lowered };
  }
}

