const PACKAGE_INDEX_FILE = "index.pactia";

export interface BindSyntaxTreeResult {
  readonly tree: BoundTree;
  readonly diagnostics: readonly Diagnostic[];
}

export function bindSyntaxTree(
  syntax: SyntaxTree,
  registry: EffectiveRegistry,
): BindSyntaxTreeResult {
  const diagnostics: Diagnostic[] = [];
  const binder = new SyntaxTreeBinder(syntax, registry, diagnostics);
  return { tree: binder.bind(), diagnostics };
}

class SyntaxTreeBinder {
  private readonly bodyItemBinder: BodyItemBinder;

  constructor(
    private readonly syntax: SyntaxTree,
    private readonly registry: EffectiveRegistry,
    private readonly diagnostics: Diagnostic[],
  ) {
    this.bodyItemBinder = new BodyItemBinder(registry, diagnostics);
  }

  bind(): BoundTree {
    this.checkExportDefsInProduct();
    this.checkConstantDefs();
    const root = this.bindProductOrEmpty(this.syntax.root);
    return { entryFile: this.syntax.entryFile, root };
  }

  private checkConstantDefs(): void {
    for (const c of this.syntax.root.constantExports) {
      if (!c.hasDef) {
        this.diagnostics.push(
          createDiagnostic(
            DiagnosticCode.ConstantDefRequired,
            `export '${c.name}' is missing 'def' keyword — use 'export def ${c.name} = ${c.value}'`,
            { location: c.location, target: c.name },
          ),
        );
      }
    }
  }

  private checkExportDefsInProduct(): void {
    if (this.syntax.entryFile === PACKAGE_INDEX_FILE) return;
    for (const def of this.syntax.root.exportDefs) {
      this.diagnostics.push(
        createDiagnostic(
          DiagnosticCode.DefInProduct,
          `export def ${def.sigil === DefSigil.Macro ? "#" : "@"}${def.name} is only allowed in package index.pactia`,
          { location: def.location, target: def.name },
        ),
      );
    }
  }

  private bindProductOrEmpty(program: ProgramNode): BoundBlockNode {
    if (!program.product) {
      return {
        kind: BoundNodeKind.BoundBlock,
        placement: PlacementTarget.Product,
        children: [],
        location: program.location,
      };
    }
    return this.bindProduct(program.product);
  }

  private bindProduct(product: ProductNode): BoundBlockNode {
    const children: BoundTreeItem[] = [];
    for (const item of product.items) {
      children.push(...this.bindProductItems(item, PlacementTarget.Product));
    }
    return {
      kind: BoundNodeKind.BoundBlock,
      placement: PlacementTarget.Product,
      hostName: product.name,
      children,
      location: product.location,
    };
  }

  private bindModule(module: ModuleNode): BoundBlockNode {
    const children: BoundTreeItem[] = [];
    for (const item of module.items) {
      children.push(...this.bindModuleItems(item, PlacementTarget.Module));
    }
    return {
      kind: BoundNodeKind.BoundBlock,
      placement: PlacementTarget.Module,
      hostName: module.name,
      children,
      location: module.location,
    };
  }

  private bindModel(model: ModelNode): BoundBlockNode {
    const children: BoundTreeItem[] = [];
    for (const item of model.items) {
      children.push(...this.bindModelItems(item, PlacementTarget.Model));
    }
    return {
      kind: BoundNodeKind.BoundBlock,
      placement: PlacementTarget.Model,
      children,
      location: model.location,
    };
  }

  private bindService(service: ServiceNode): BoundBlockNode {
    const children: BoundTreeItem[] = [];
    for (const item of service.items) {
      children.push(...this.bindServiceItems(item, PlacementTarget.Service));
    }
    return {
      kind: BoundNodeKind.BoundBlock,
      placement: PlacementTarget.Service,
      hostName: service.name,
      children,
      location: service.location,
    };
  }

  private bindProductItems(item: ProductItem, enclosing: PlacementTarget): BoundTreeItem[] {
    switch (item.kind) {
      case SyntaxNodeKind.Module:
        return [this.bindModule(item)];
      case SyntaxNodeKind.AttachModule:
        return [];
      case SyntaxNodeKind.Context:
        return this.bindContextBlock(item);
      case SyntaxNodeKind.ContextAttach:
        return this.bindContextAttach(item);
      default:
        return this.bindTagLikeItems([item], enclosing);
    }
  }

  private bindModuleItems(item: ModuleItem, enclosing: PlacementTarget): BoundTreeItem[] {
    switch (item.kind) {
      case SyntaxNodeKind.Service:
        return [this.bindService(item)];
      case SyntaxNodeKind.Model:
        return [this.bindModel(item)];
      case SyntaxNodeKind.DefExport:
      case SyntaxNodeKind.DefLocal:
        return [this.bindDefDecl(item)];
      case SyntaxNodeKind.ModuleConst:
        return [item];
      case SyntaxNodeKind.Context:
        return this.bindContextBlock(item);
      case SyntaxNodeKind.ContextAttach:
        return this.bindContextAttach(item);
      default:
        return this.bindTagLikeItems([item], enclosing);
    }
  }

  private bindModelItems(item: ModelItem, enclosing: PlacementTarget): BoundTreeItem[] {
    switch (item.kind) {
      case SyntaxNodeKind.Context:
        return this.bindContextBlock(item);
      case SyntaxNodeKind.ContextAttach:
        return this.bindContextAttach(item);
      default:
        return this.bindTagLikeItems([item], enclosing);
    }
  }

  private bindServiceItems(item: ServiceItem, enclosing: PlacementTarget): BoundTreeItem[] {
    switch (item.kind) {
      case SyntaxNodeKind.Context:
        return this.bindContextBlock(item);
      case SyntaxNodeKind.ContextAttach:
        return this.bindContextAttach(item);
      default:
        return this.bindTagLikeItems([item], enclosing);
    }
  }

  private bindTagLikeItems(
    items: readonly (ProductItem | ModuleItem | ModelItem | ServiceItem | TagBodyItem)[],
    enclosing: PlacementTarget,
  ): BoundTreeItem[] {
    const tagBodyItems = items.filter(
      (item): item is TagBodyItem =>
        item.kind === SyntaxNodeKind.TagBlock ||
        item.kind === SyntaxNodeKind.TagPrefix ||
        item.kind === SyntaxNodeKind.MacroInvocation ||
        item.kind === SyntaxNodeKind.FieldLine ||
        item.kind === SyntaxNodeKind.Prose,
    );
    return this.bodyItemBinder.bindItems(tagBodyItems, enclosing);
  }

  private bindContextBlock(block: ContextBlockNode): BoundTreeItem[] {
    const bound = this.toBoundContext(block.name, block.pathRaw, block.guidance, block.location);
    return bound ? [bound] : [];
  }

  private bindContextAttach(attach: ContextAttachNode): BoundTreeItem[] {
    const exported = this.registry.contexts.get(attach.symbol);
    if (!exported) {
      this.diagnostics.push(
        createDiagnostic(
          DiagnosticCode.ContextAttachUndefined,
          `Context attach references undefined symbol '${attach.symbol}'`,
          { location: attach.location, target: attach.symbol },
        ),
      );
      return [];
    }
    const bound = this.toBoundContext(
      attach.symbol,
      exported.pathRaw,
      exported.guidance,
      attach.location,
      exported.coordinate,
    );
    return bound ? [bound] : [];
  }

  private toBoundContext(
    name: string,
    pathRaw: string | undefined,
    guidance: readonly string[],
    location: ContextBlockNode["location"],
    packageCoordinate?: string,
  ): BoundContextNode | undefined {
    const path = parseContextPathField(pathRaw);
    if (!path) {
      this.diagnostics.push(
        createDiagnostic(
          DiagnosticCode.ContextMissingPath,
          `Context '${name}' is missing required path field`,
          { location, target: name },
        ),
      );
      return undefined;
    }
    return {
      kind: BoundNodeKind.BoundContext,
      name,
      path,
      guidance,
      packageCoordinate,
      location,
    };
  }

  private bindDefDecl(def: DefDeclNode): BoundDefNode {
    const entry = this.resolveDefEntry(def);
    if (def.exported && this.syntax.entryFile !== PACKAGE_INDEX_FILE) {
      // Diagnostic already emitted in checkExportDefsInProduct for root export defs.
    }
    return {
      kind: BoundNodeKind.BoundDef,
      name: def.name,
      exported: def.exported,
      registryEntry: entry,
      location: def.location,
    };
  }

  private resolveDefEntry(def: DefDeclNode): BoundDefNode["registryEntry"] {
    if (def.sigil === DefSigil.Macro) {
      const entry = this.registry.macros.get(def.name);
      if (entry) return entry;
      this.diagnostics.push(
        createDiagnostic(
          DiagnosticCode.MacroUnknown,
          `Unknown macro def '#${def.name}'`,
          { location: def.location, target: def.name },
        ),
      );
      return {
        kind: RegistryEntryKind.Macro,
        name: def.name,
        source: "unresolved",
        in: [],
        params: [],
        body: { lines: [], items: [] },
      };
    }

    const entry = this.registry.tags.get(def.name);
    if (entry) return entry;
    this.diagnostics.push(
      createDiagnostic(
        DiagnosticCode.UnknownSymbol,
        `Unknown tag def '@${def.name}'`,
        { location: def.location, target: def.name },
      ),
    );
    return {
      kind: RegistryEntryKind.Tag,
      name: def.name,
      source: "unresolved",
      in: [],
      fields: { required: [], optional: [], modifier: false, openExtension: false },
      modifier: false,
      ir: { file: IrFile.Product, path: IrBodySlot.BodyArray, merge: IrMerge.AppendHost },
    };
  }
}

import {
  BoundNodeKind,
  DiagnosticCode,
  IrBodySlot,
  IrFile,
  IrMerge,
  PlacementTarget,
  RegistryEntryKind,
  createDiagnostic,
  type BoundMacroNode,
  type BoundTagNode,
  type BoundTreeItem,
  type EffectiveRegistry,
} from "../../domain/index.js";
import type { Diagnostic } from "../../domain/diagnostics.js";
import {
  SyntaxNodeKind,
  type MacroInvocationNode,
  type TagBlockNode,
  type TagBodyItem,
  type TagPrefixNode,
  type SourceLocation,
} from "../../domain/syntax-tree.js";

export class BodyItemBinder {
  constructor(
    private readonly registry: EffectiveRegistry,
    private readonly diagnostics: Diagnostic[],
  ) {}

  bindItems(items: readonly TagBodyItem[], enclosing: PlacementTarget): BoundTreeItem[] {
    const bound: BoundTreeItem[] = [];
    for (const item of items) {
      switch (item.kind) {
        case SyntaxNodeKind.TagBlock:
          bound.push(this.bindTagBlock(item, enclosing));
          break;
        case SyntaxNodeKind.TagPrefix:
          bound.push(this.bindTagPrefix(item, enclosing));
          break;
        case SyntaxNodeKind.MacroInvocation:
          bound.push(this.bindMacroInvocation(item, enclosing));
          break;
        case SyntaxNodeKind.FieldLine:
        case SyntaxNodeKind.Prose:
          bound.push(item);
          break;
        default:
          break;
      }
    }
    return bound;
  }

  private bindTagBlock(tag: TagBlockNode, enclosing: PlacementTarget): BoundTagNode {
    const entry = this.resolveTag(tag.tagName, tag.location);
    return {
      kind: BoundNodeKind.BoundTag,
      tagName: tag.tagName,
      hostId: tag.hostId,
      registryEntry: entry,
      enclosing,
      children: this.bindItems(tag.items, enclosing),
      location: tag.location,
    };
  }

  private bindTagPrefix(tag: TagPrefixNode, enclosing: PlacementTarget): BoundTagNode {
    const entry = this.resolveTag(tag.tagName, tag.location);
    return {
      kind: BoundNodeKind.BoundTag,
      tagName: tag.tagName,
      shorthand: tag.shorthand,
      registryEntry: entry,
      enclosing,
      children: [],
      location: tag.location,
    };
  }

  private bindMacroInvocation(
    macro: MacroInvocationNode,
    enclosing: PlacementTarget,
  ): BoundMacroNode {
    const entry = this.resolveMacro(macro.name, macro.location);
    return {
      kind: BoundNodeKind.BoundMacro,
      name: macro.name,
      registryEntry: entry,
      enclosing,
      args: macro.args,
      location: macro.location,
    };
  }

  private resolveTag(tagName: string, location: SourceLocation): BoundTagNode["registryEntry"] {
    const entry = this.registry.tags.get(tagName);
    if (!entry) {
      this.diagnostics.push(
        createDiagnostic(DiagnosticCode.UnknownSymbol, `Unknown tag '@${tagName}'`, {
          location,
          target: tagName,
        }),
      );
      return this.stubTagEntry(tagName);
    }
    return entry;
  }

  private resolveMacro(
    macroName: string,
    location: SourceLocation,
  ): BoundMacroNode["registryEntry"] {
    const entry = this.registry.macros.get(macroName);
    if (!entry) {
      this.diagnostics.push(
        createDiagnostic(DiagnosticCode.MacroUnknown, `Unknown macro '#${macroName}'`, {
          location,
          target: macroName,
        }),
      );
      return this.stubMacroEntry(macroName);
    }
    return entry;
  }

  private stubTagEntry(name: string): BoundTagNode["registryEntry"] {
    return {
      kind: RegistryEntryKind.Tag,
      name,
      source: "unresolved",
      in: [],
      fields: { required: [], optional: [], modifier: false, openExtension: false },
      modifier: false,
      ir: { file: IrFile.Product, path: IrBodySlot.BodyArray, merge: IrMerge.AppendHost },
    };
  }

  private stubMacroEntry(name: string): BoundMacroNode["registryEntry"] {
    return {
      kind: RegistryEntryKind.Macro,
      name,
      source: "unresolved",
      in: [],
      params: [],
      body: { lines: [], items: [] },
    };
  }
}

import {
  BoundNodeKind,
  DiagnosticCode,
  placementAllows,
  createDiagnostic,
  type BoundBlockNode,
  type BoundMacroNode,
  type BoundTree,
  type BoundTreeItem,
  type EffectiveRegistry,
} from "../../domain/index.js";
import type { Diagnostic } from "../../domain/diagnostics.js";
import {
  SyntaxNodeKind,
  type FieldLineNode,
  type ProseNode,
  type SourceLocation,
  type TagBodyItem,
  type TagBlockNode,
  type MacroInvocationNode,
  type TagPrefixNode,
} from "../../domain/syntax-tree.js";
import { BodyItemBinder } from "../bind/body-item-binder.js";

const MAX_EXPANSION_PASSES = 64;
const PARAM_PATTERN = /\$\{([^}]+)\}/g;

export interface ExpandBoundTreeResult {
  readonly tree: BoundTree;
  readonly diagnostics: readonly Diagnostic[];
}

export function expandBoundTree(
  tree: BoundTree,
  registry: EffectiveRegistry,
  expansionRegistry: EffectiveRegistry = registry,
): ExpandBoundTreeResult {
  const diagnostics: Diagnostic[] = [];
  let root = tree.root;
  let pass = 0;

  while (containsMacroNode(root) && pass < MAX_EXPANSION_PASSES) {
    const expander = new MacroExpander(registry, expansionRegistry, diagnostics);
    root = expander.expandBlock(root, new Set());
    pass += 1;
  }

  if (containsMacroNode(root)) {
    diagnostics.push(
      createDiagnostic(
        DiagnosticCode.MacroExpansionCycle,
        "Macro expansion did not reach a fixed point",
      ),
    );
  }

  return { tree: { entryFile: tree.entryFile, root }, diagnostics };
}

class MacroExpander {
  private readonly binder: BodyItemBinder;

  constructor(
    private readonly registry: EffectiveRegistry,
    expansionRegistry: EffectiveRegistry,
    private readonly diagnostics: Diagnostic[],
  ) {
    this.binder = new BodyItemBinder(expansionRegistry, diagnostics);
  }

  expandBlock(block: BoundBlockNode, visiting: Set<string>): BoundBlockNode {
    return {
      ...block,
      children: this.expandItems(block.children, block.placement, visiting),
    };
  }

  private expandItems(
    items: readonly BoundTreeItem[],
    enclosing: BoundBlockNode["placement"],
    visiting: Set<string>,
  ): BoundTreeItem[] {
    const expanded: BoundTreeItem[] = [];
    for (const item of items) {
      expanded.push(...this.expandItem(item, enclosing, visiting));
    }
    return expanded;
  }

  private expandItem(
    item: BoundTreeItem,
    enclosing: BoundBlockNode["placement"],
    visiting: Set<string>,
  ): BoundTreeItem[] {
    if (item.kind === BoundNodeKind.BoundMacro) {
      return this.expandMacro(item, enclosing, visiting);
    }
    if (item.kind === BoundNodeKind.BoundBlock) {
      return [this.expandBlock(item, visiting)];
    }
    if (item.kind === BoundNodeKind.BoundTag) {
      return [
        {
          ...item,
          children: this.expandItems(item.children, enclosing, visiting),
        },
      ];
    }
    return [item];
  }

  private expandMacro(
    macro: BoundMacroNode,
    enclosing: BoundBlockNode["placement"],
    visiting: Set<string>,
  ): BoundTreeItem[] {
    const entry = macro.registryEntry;
    if (entry.source === "unresolved") {
      return [macro];
    }

    if (!placementAllows(entry.in, macro.enclosing)) {
      this.diagnostics.push(
        createDiagnostic(
          DiagnosticCode.PlacementViolation,
          `Macro '#${macro.name}' is not allowed in ${macro.enclosing}`,
          { location: macro.location, target: macro.name },
        ),
      );
      return [macro];
    }

    if (macro.args.length !== entry.params.length) {
      this.diagnostics.push(
        createDiagnostic(
          DiagnosticCode.MacroArgsInvalid,
          `Macro '#${macro.name}' expects ${entry.params.length} argument(s), got ${macro.args.length}`,
          { location: macro.location, target: macro.name },
        ),
      );
      return [macro];
    }

    if (visiting.has(macro.name)) {
      this.diagnostics.push(
        createDiagnostic(
          DiagnosticCode.MacroExpansionCycle,
          `Macro expansion cycle detected at '#${macro.name}'`,
          { location: macro.location, target: macro.name },
        ),
      );
      return [macro];
    }

    visiting.add(macro.name);
    const substituted = substituteBodyItems(
      entry.body.items,
      entry.params,
      macro.args,
      macro.location,
    );
    const spliced = this.binder.bindItems(substituted, enclosing);

    const expanded: BoundTreeItem[] = [];
    for (const item of spliced) {
      expanded.push(...this.expandItem(item, enclosing, visiting));
    }
    visiting.delete(macro.name);
    return expanded;
  }
}

function containsMacroNode(block: BoundBlockNode): boolean {
  return block.children.some((child) => treeItemContainsMacro(child));
}

function treeItemContainsMacro(item: BoundTreeItem): boolean {
  if (item.kind === BoundNodeKind.BoundMacro) return true;
  if (item.kind === BoundNodeKind.BoundBlock) return containsMacroNode(item);
  if (item.kind === BoundNodeKind.BoundTag) {
    return item.children.some((child) => treeItemContainsMacro(child));
  }
  return false;
}

function substituteBodyItems(
  items: readonly TagBodyItem[],
  params: readonly string[],
  args: readonly string[],
  location: SourceLocation,
): TagBodyItem[] {
  const bindings = new Map<string, string>();
  for (let index = 0; index < params.length; index += 1) {
    bindings.set(params[index]!, args[index] ?? "");
  }

  return items.map((item) => substituteBodyItem(item, bindings, location));
}

function substituteBodyItem(
  item: TagBodyItem,
  bindings: Map<string, string>,
  location: SourceLocation,
): TagBodyItem {
  switch (item.kind) {
    case SyntaxNodeKind.FieldLine:
      return substituteFieldLine(item, bindings, location);
    case SyntaxNodeKind.Prose:
      return substituteProse(item, bindings, location);
    case SyntaxNodeKind.TagBlock:
      return substituteTagBlock(item, bindings, location);
    case SyntaxNodeKind.TagPrefix:
      return substituteTagPrefix(item, bindings, location);
    case SyntaxNodeKind.MacroInvocation:
      return substituteMacroInvocation(item, bindings, location);
    default:
      return item;
  }
}

function substituteFieldLine(
  item: FieldLineNode,
  bindings: Map<string, string>,
  location: SourceLocation,
): FieldLineNode {
  if (item.value === undefined) return { ...item, location: mergeLocation(item.location, location) };
  return {
    ...item,
    value: substituteText(item.value, bindings),
    location: mergeLocation(item.location, location),
  };
}

function substituteProse(
  item: ProseNode,
  bindings: Map<string, string>,
  location: SourceLocation,
): ProseNode {
  return {
    ...item,
    text: substituteText(item.text, bindings),
    location: mergeLocation(item.location, location),
  };
}

function substituteTagBlock(
  item: TagBlockNode,
  bindings: Map<string, string>,
  location: SourceLocation,
): TagBlockNode {
  return {
    ...item,
    items: item.items.map((child) => substituteBodyItem(child, bindings, location)),
    location: mergeLocation(item.location, location),
  };
}

function substituteTagPrefix(
  item: TagPrefixNode,
  bindings: Map<string, string>,
  location: SourceLocation,
): TagPrefixNode {
  return {
    ...item,
    shorthand: item.shorthand ? substituteText(item.shorthand, bindings) : undefined,
    location: mergeLocation(item.location, location),
  };
}

function substituteMacroInvocation(
  item: MacroInvocationNode,
  bindings: Map<string, string>,
  location: SourceLocation,
): MacroInvocationNode {
  return {
    ...item,
    args: item.args.map((arg) => substituteText(arg, bindings)),
    location: mergeLocation(item.location, location),
  };
}

function substituteText(text: string, bindings: Map<string, string>): string {
  if (bindings.has(text)) {
    return bindings.get(text) ?? text;
  }
  return text.replace(PARAM_PATTERN, (_match, name: string) => bindings.get(name) ?? "");
}

function mergeLocation(original: SourceLocation, fallback: SourceLocation): SourceLocation {
  return {
    file: original.file || fallback.file,
    line: original.line || fallback.line,
    col: original.col || fallback.col,
    span: original.span ?? fallback.span,
  };
}

/**
 * Phase 8 — validate tag body fields against registry def field specs.
 *
 * Walks the bound tree after macro expansion. For every BoundTagNode:
 *   1. Checks all required fields from the registry def are present.
 *   2. Warns on fields not declared in required + optional (openExtension bypasses).
 *   3. Flags duplicate field names within a single tag body.
 *
 * Placement is already enforced in the bind phase (PLACEMENT_VIOLATION).
 * No tag-name-specific checks — all tags use the same uniform validation path.
 */

import {
  BoundNodeKind,
  DiagnosticCode,
  createDiagnostic,
  type BoundBlockNode,
  type BoundTagNode,
  type BoundTree,
  type BoundTreeItem,
} from "../../domain/index.js";
import type { Diagnostic } from "../../domain/diagnostics.js";
import { SyntaxNodeKind, type FieldLineNode } from "../../domain/syntax-tree.js";

export const passName = "validate" as const;

export interface ValidateBoundTreeResult {
  readonly diagnostics: readonly Diagnostic[];
}

export function validateBoundTree(tree: BoundTree): ValidateBoundTreeResult {
  const diagnostics: Diagnostic[] = [];
  walkBoundBlock(tree.root, diagnostics);
  return { diagnostics };
}

function walkBoundBlock(block: BoundBlockNode, diagnostics: Diagnostic[]): void {
  for (const child of block.children) {
    walkBoundItem(child, diagnostics);
  }
}

function walkBoundItem(item: BoundTreeItem, diagnostics: Diagnostic[]): void {
  if (item.kind === BoundNodeKind.BoundBlock) {
    walkBoundBlock(item, diagnostics);
    return;
  }
  if (item.kind === BoundNodeKind.BoundTag) {
    validateTagFields(item, diagnostics);
    // Also recurse into nested tag children
    for (const child of item.children) {
      if (
        child.kind === BoundNodeKind.BoundBlock ||
        child.kind === BoundNodeKind.BoundTag
      ) {
        walkBoundItem(child, diagnostics);
      }
    }
    return;
  }
  // BoundMacroNode, BoundDefNode, BoundContextNode — nothing to validate here.
  // FieldLineNode, ProseNode, ModuleConstNode, ContextBlockNode — leaves.
}

function collectFieldNames(
  items: readonly BoundTreeItem[],
): { names: string[]; locations: Map<string, number> } {
  const names: string[] = [];
  const locations = new Map<string, number>();
  for (const item of items) {
    if (item.kind === SyntaxNodeKind.FieldLine) {
      const field = item as FieldLineNode;
      names.push(field.name);
      if (!locations.has(field.name)) {
        locations.set(field.name, field.location.line);
      }
    }
  }
  return { names, locations };
}

function validateTagFields(
  tag: BoundTagNode,
  diagnostics: Diagnostic[],
): void {
  // Modifier tags (@@name) merge into the next host — they are not standalone.
  if (tag.registryEntry.modifier) return;

  const spec = tag.registryEntry.fields;
  const { names, locations } = collectFieldNames(tag.children);

  // 1. Check required fields present
  for (const required of spec.required) {
    if (!names.includes(required)) {
      diagnostics.push(
        createDiagnostic(
          DiagnosticCode.TagBodyMissingField,
          `@${tag.tagName} is missing required field '${required}'`,
          { location: tag.location },
        ),
      );
    }
  }

  // 2. Check unknown fields (skip if openExtension)
  if (!spec.openExtension) {
    const known = new Set([...spec.required, ...spec.optional]);
    for (const name of names) {
      if (!known.has(name)) {
        diagnostics.push(
          createDiagnostic(
            DiagnosticCode.TagBodyUnknownField,
            `@${tag.tagName} has unknown field '${name}'`,
            { location: tag.location },
          ),
        );
      }
    }
  }

  // 3. Check duplicate field names
  const seen = new Set<string>();
  for (const name of names) {
    if (seen.has(name)) {
      diagnostics.push(
        createDiagnostic(
          DiagnosticCode.ClauseDuplicateKey,
          `@${tag.tagName} has duplicate field '${name}'`,
          { location: tag.location },
        ),
      );
    }
    seen.add(name);
  }
}

import { Provenance } from "../../domain/provenance.js";
import { IrBodyKind, IrBodySlot, IrContextSlot } from "../../domain/ir-body.js";
import type { WorkspaceIr } from "../../domain/workspace-ir.js";
import {
  BoundNodeKind,
  DiagnosticCode,
  IrFile,
  IrMerge,
  PlacementTarget,
  createDiagnostic,
  type BoundBlockNode,
  type BoundContextNode,
  type BoundTagNode,
  type BoundTree,
  type BoundTreeItem,
} from "../../domain/index.js";
import type { Diagnostic } from "../../domain/diagnostics.js";
import type { RegistryTagEntry } from "../../domain/registry.js";
import { SyntaxNodeKind, type FieldLineNode, type ProseNode } from "../../domain/syntax-tree.js";
import { emitIrFileMap } from "../../adapters/json-emitter.js";
import { serviceFileStem } from "../../frontend/kernel/text.js";
import {
  IrRelativePath,
  moduleIrPaths,
  serviceIrPath,
} from "../../domain/workspace-ir.js";
import { mergeDeep, getAtPath, parseScalarValue, setAtPath } from "../../lower/ir-path.js";
import {
  appendHostObject,
  appendModifierTag,
  applyRegistryTagLabel,
  boundLeafBodyToObject,
  mergePrefixShorthand,
  mergeTagBlock,
  parseIrPath,
} from "./ir-slot-writer.js";

const COMPILED_AT = "1970-01-01T00:00:00.000Z";

export interface LowerBoundTreeInput {
  readonly tree: BoundTree;
  readonly pactiaVersion: string;
  readonly entryFile: string;
  readonly lockfileDigest?: string;
}

export interface LowerBoundTreeResult {
  readonly workspace: WorkspaceIr;
  readonly files: ReadonlyMap<string, string>;
  readonly diagnostics: readonly Diagnostic[];
}

type WritableRecord = Record<string, unknown>;

/** In-memory IR during lowering — slots appear only when registry paths write them. */
interface LazyModuleBundle {
  readonly module: { readonly module: WritableRecord };
  readonly model: { readonly model: WritableRecord };
  readonly services: Array<{ readonly service: WritableRecord }>;
}

interface CrossFileBind {
  readonly service: string;
  readonly endpoint?: string;
}

interface LowerFrame {
  readonly crossFileBind?: CrossFileBind;
}

export function lowerBoundTree(input: LowerBoundTreeInput): LowerBoundTreeResult {
  const diagnostics: Diagnostic[] = [];
  const lowerer = new BoundTreeLowerer(input, diagnostics);
  const workspace = lowerer.lower();
  const fileObjects = workspaceToFileObjects(workspace);
  return {
    workspace,
    files: emitIrFileMap(fileObjects),
    diagnostics,
  };
}

class BoundTreeLowerer {
  private readonly modules: LazyModuleBundle[] = [];
  private productDoc: WritableRecord = {};
  private currentModule: LazyModuleBundle | undefined;
  private serviceRoot: WritableRecord | undefined;
  private pendingHost: WritableRecord = {};

  constructor(
    private readonly input: LowerBoundTreeInput,
    private readonly diagnostics: Diagnostic[],
  ) {}

  lower(): WorkspaceIr {
    const root = this.input.tree.root;
    if (root.hostName && root.placement === PlacementTarget.Product) {
      this.productDoc = {
        name: root.hostName,
      };
      this.lowerBlock(root);
    } else {
      for (const child of root.children) {
        this.lowerTreeItem(child, IrFile.Product);
      }
    }

    if (this.modules.length === 0) {
      this.diagnostics.push(
        createDiagnostic(DiagnosticCode.ParseError, "Lower requires at least one module"),
      );
    }

    return {
      manifest: {
        manifest: {
          pactiaVersion: this.input.pactiaVersion,
          compiledAt: COMPILED_AT,
          entry: this.input.entryFile,
          lockfileDigest: this.input.lockfileDigest ?? `sha256:${"0".repeat(64)}`,
          modules: this.modules.map((bundle) => {
            const moduleName = String(bundle.module.module["name"]);
            return {
              name: moduleName,
              path: `modules/${moduleName}/`,
              module: `${moduleName}.module.json`,
              model: `${moduleName}.model.json`,
              services: bundle.services.map((serviceSlice) => {
                const stem = serviceFileStem(String(serviceSlice.service["name"]));
                return {
                  name: stem,
                  file: `services/${stem}.service.json`,
                };
              }),
            };
          }),
          references: [],
        },
      },
      product: { product: this.productDoc },
      modules: this.modules,
    } as WorkspaceIr;
  }

  private lowerTreeItem(item: BoundTreeItem, scopeFile: IrFile): void {
    if (item.kind === BoundNodeKind.BoundBlock) {
      this.lowerBlock(item);
      return;
    }
    if (item.kind === SyntaxNodeKind.Prose) {
      this.appendProseLine(item, scopeFile);
      return;
    }
    if (item.kind === BoundNodeKind.BoundTag) {
      this.lowerRegistryTag(item, {}, scopeFile);
      return;
    }
    if (item.kind === BoundNodeKind.BoundContext) {
      this.lowerBoundContext(item, scopeFile);
      return;
    }
    if (item.kind === SyntaxNodeKind.FieldLine && scopeFile === IrFile.Service) {
      this.applyServiceFieldLine(item);
    }
  }

  private lowerBoundContext(context: BoundContextNode, scopeFile: IrFile): void {
    const entry: WritableRecord = {
      name: context.name,
      path: context.path,
      provenance: Provenance.Pactia,
    };
    if (context.guidance.length > 0) {
      entry["guidance"] = [...context.guidance];
    }
    if (context.packageCoordinate) {
      entry["package"] = context.packageCoordinate;
    }
    this.appendContextEntry(scopeFile, entry);
  }

  private appendContextEntry(scopeFile: IrFile, entry: WritableRecord): void {
    const root = this.documentRoot(scopeFile);
    const key = IrContextSlot.ContextArray;
    const existing = root[key];
    if (!Array.isArray(existing)) {
      root[key] = [entry];
      return;
    }
    existing.push(entry);
  }

  private appendProseLine(prose: ProseNode, scopeFile: IrFile): void {
    if (prose.text.length === 0) return;
    appendHostObject(this.documentRoot(scopeFile), IrBodySlot.BodyArray, {
      kind: IrBodyKind.Prose,
      text: prose.text,
      provenance: Provenance.Guidance,
    });
  }

  private lowerBlock(block: BoundBlockNode): void {
    switch (block.placement) {
      case PlacementTarget.Product: {
        for (const child of block.children) {
          this.lowerTreeItem(child, IrFile.Product);
        }
        break;
      }
      case PlacementTarget.Module:
        this.openModule(block.hostName ?? "module");
        for (const child of block.children) {
          if (child.kind === BoundNodeKind.BoundBlock && child.placement === PlacementTarget.Model) {
            this.lowerModelBlock(child);
            continue;
          }
          if (child.kind === BoundNodeKind.BoundBlock && child.placement === PlacementTarget.Service) {
            this.lowerServiceBlock(child);
            continue;
          }
          this.lowerTreeItem(child, IrFile.Module);
        }
        break;
      default:
        break;
    }
  }

  private openModule(name: string): void {
    const bundle: LazyModuleBundle = {
      module: { module: { name } },
      model: { model: { name } },
      services: [],
    };
    this.currentModule = bundle;
    this.modules.push(bundle);
  }

  private lowerModelBlock(block: BoundBlockNode): void {
    if (!this.currentModule) return;
    for (const child of block.children) {
      this.lowerTreeItem(child, IrFile.Model);
    }
  }

  private lowerServiceBlock(block: BoundBlockNode): void {
    if (!this.currentModule || !block.hostName) return;

    this.pendingHost = {};
    this.serviceRoot = { name: block.hostName };

    for (const child of block.children) {
      this.lowerTreeItem(child, IrFile.Service);
    }

    this.currentModule.services.push({ service: this.serviceRoot });
    this.serviceRoot = undefined;
    this.pendingHost = {};
  }

  private applyServiceFieldLine(line: FieldLineNode): void {
    if (!this.serviceRoot || line.value === undefined) return;
    const value = parseScalarValue(line.value);
    if (line.name.startsWith("flags.")) {
      setAtPath(this.serviceRoot, line.name, value);
      return;
    }
    setAtPath(this.pendingHost, line.name, value);
  }

  private lowerRegistryTag(
    tag: BoundTagNode,
    frame: LowerFrame,
    scopeFile: IrFile,
  ): void {
    const entry = tag.registryEntry;
    if (entry.source === "unresolved") return;

    switch (entry.ir.merge) {
      case IrMerge.AppendHost:
        this.lowerAppendHost(tag, frame, scopeFile);
        break;
      case IrMerge.MergeIntoHost:
        this.lowerMergeIntoHost(tag, scopeFile);
        break;
      case IrMerge.MergeFields:
        this.lowerMergeFieldsHost(tag);
        break;
      case IrMerge.FieldAnnotation:
        break;
      default:
        break;
    }
  }

  private lowerMergeFieldsHost(tag: BoundTagNode): void {
    const entry = tag.registryEntry;
    const host: WritableRecord = {
      ...boundLeafBodyToObject(this.nonTagBodyItems(tag.children)),
    };
    applyRegistryTagLabel(host, entry.name);
    host["provenance"] = Provenance.Pactia;
    if (tag.shorthand !== undefined) {
      mergePrefixShorthand(host, entry, tag.shorthand);
    }
    appendHostObject(this.documentRoot(entry.ir.file), IrBodySlot.BodyArray, host);
  }

  private lowerMergeIntoHost(tag: BoundTagNode, scopeFile: IrFile): void {
    const entry = tag.registryEntry;
    const target =
      scopeFile === IrFile.Service && this.serviceRoot
        ? this.pendingHost
        : this.documentRoot(entry.ir.file);

    appendModifierTag(target, entry.name);

    if (tag.shorthand !== undefined) {
      mergePrefixShorthand(target, entry, tag.shorthand);
      return;
    }
    mergeTagBlock(target, entry, tag.children);
  }

  private lowerAppendHost(
    tag: BoundTagNode,
    frame: LowerFrame,
    scopeFile: IrFile,
  ): void {
    const entry = tag.registryEntry;
    const root = this.documentRoot(entry.ir.file);

    if (this.isProseOnlyBody(tag) && parseIrPath(entry.ir.path).appendArray) {
      for (const child of tag.children) {
        if (child.kind === SyntaxNodeKind.Prose && child.text.length > 0) {
          appendHostObject(root, entry.ir.path, {
            tag: entry.name,
            text: child.text,
            provenance: Provenance.Guidance,
          });
        }
      }
      return;
    }

    const host = this.buildAppendHost(tag, frame);
    for (const child of tag.children) {
      if (child.kind !== BoundNodeKind.BoundTag) continue;
      const childEntry = child.registryEntry;
      if (childEntry.ir.file !== entry.ir.file) {
        this.lowerRegistryTag(child, {
          crossFileBind: {
            service: String(this.serviceRoot?.["name"] ?? ""),
            endpoint: tag.hostId,
          },
        }, scopeFile);
        continue;
      }
      this.applyNestedTag(host, entry, child, frame);
    }

    host["provenance"] = Provenance.Pactia;
    appendHostObject(root, entry.ir.path, host);
  }

  private buildAppendHost(
    tag: BoundTagNode,
    frame: LowerFrame,
  ): WritableRecord {
    const entry = tag.registryEntry;
    const host: WritableRecord = { ...this.pendingHost };
    this.pendingHost = {};

    applyRegistryTagLabel(host, entry.name);

    this.applyHostIdentity(host, tag, entry);

    if (tag.shorthand !== undefined) {
      mergePrefixShorthand(host, entry, tag.shorthand);
    }

    if (this.isOpenFieldHost(entry)) {
      this.collectOpenFieldHostBody(host, tag.children);
    } else {
      mergeDeep(host, boundLeafBodyToObject(this.nonTagBodyItems(tag.children)));
    }

    this.enrichAppendHost(host, entry, tag.enclosing, frame);
    this.promoteSummaryToText(host);
    return host;
  }

  /** Host identity key follows IR file conventions — model type hosts use `name`. */
  private applyHostIdentity(
    host: WritableRecord,
    tag: BoundTagNode,
    entry: RegistryTagEntry,
  ): void {
    if (!tag.hostId) return;
    const key = entry.ir.file === IrFile.Model ? "name" : "id";
    host[key] = tag.hostId;
  }

  /** Model `@entity` bodies — field lines are typed columns, not tag body key-value pairs. */
  private isOpenFieldHost(entry: RegistryTagEntry): boolean {
    return (
      entry.ir.file === IrFile.Model &&
      entry.fields.openExtension &&
      entry.fields.required.length === 0 &&
      entry.fields.optional.length === 0
    );
  }

  private applyNestedTag(
    parentHost: WritableRecord,
    _parentEntry: RegistryTagEntry,
    tag: BoundTagNode,
    frame: LowerFrame,
  ): void {
    const entry = tag.registryEntry;
    const slotPath = IrBodySlot.BodyArray;

    switch (entry.ir.merge) {
      case IrMerge.AppendHost: {
        const host = this.buildAppendHost(tag, frame);
        for (const child of tag.children) {
          if (child.kind === BoundNodeKind.BoundTag) {
            this.applyNestedTag(host, entry, child, frame);
          }
        }
        host["provenance"] = Provenance.Pactia;
        appendHostObject(parentHost, slotPath, host);
        break;
      }
      case IrMerge.MergeIntoHost:
        if (tag.shorthand !== undefined) {
          mergePrefixShorthand(parentHost, entry, tag.shorthand);
        } else {
          mergeTagBlock(parentHost, { ...entry, ir: { ...entry.ir, path: slotPath } }, tag.children);
        }
        break;
      case IrMerge.MergeFields: {
        const host = boundLeafBodyToObject(this.nonTagBodyItems(tag.children));
        applyRegistryTagLabel(host, entry.name);
        host["provenance"] = Provenance.Pactia;
        if (tag.shorthand !== undefined) {
          mergePrefixShorthand(host, entry, tag.shorthand);
        }
        appendHostObject(parentHost, IrBodySlot.BodyArray, host);
        break;
      }
      default:
        break;
    }
  }

  private enrichAppendHost(
    host: WritableRecord,
    entry: RegistryTagEntry,
    enclosing: PlacementTarget,
    frame: LowerFrame,
  ): void {
    if (
      enclosing === PlacementTarget.Module &&
      entry.ir.file === IrFile.Product &&
      this.currentModule &&
      host["module"] === undefined
    ) {
      host["module"] = this.currentModule.module.module["name"];
    }

    if (frame.crossFileBind && entry.ir.file === IrFile.Product && host["bind"] === undefined) {
      host["bind"] = {
        service: frame.crossFileBind.service,
        endpoint: frame.crossFileBind.endpoint,
      };
    }
  }

  private isProseOnlyBody(tag: BoundTagNode): boolean {
    return (
      tag.children.length > 0 &&
      tag.children.every((child) => child.kind === SyntaxNodeKind.Prose)
    );
  }

  private collectOpenFieldHostBody(host: WritableRecord, items: readonly BoundTreeItem[]): void {
    const fields: WritableRecord[] = [];
    let currentField: WritableRecord | undefined;

    for (const item of items) {
      if (item.kind === SyntaxNodeKind.FieldLine) {
        currentField = this.parseModelFieldLine(item);
        fields.push(currentField);
        continue;
      }
      if (
        item.kind === BoundNodeKind.BoundTag &&
        item.registryEntry.ir.merge === IrMerge.FieldAnnotation &&
        currentField
      ) {
        this.applyFieldAnnotation(currentField, item);
      }
    }

    host["fields"] = fields;
  }

  private parseModelFieldLine(line: FieldLineNode): WritableRecord {
    const raw = (line.value ?? "unknown").trim();
    const array = raw.endsWith("[]");
    const baseType = array ? raw.slice(0, -2).trim() : raw;
    return {
      name: line.name,
      type: this.normalizeFieldType(baseType),
      array,
      optional: !line.required && line.value === undefined,
    };
  }

  /** Uppercase enum-like tokens; preserve package name segment after `/`. */
  private normalizeFieldType(raw: string): string {
    const value = String(parseScalarValue(raw));
    const slash = value.indexOf("/");
    if (slash > 0) {
      return `${value.slice(0, slash).toUpperCase()}${value.slice(slash)}`;
    }
    return value.toUpperCase();
  }

  private applyFieldAnnotation(field: WritableRecord, tag: BoundTagNode): void {
    const entry = tag.registryEntry;
    appendModifierTag(field, entry.name);
    const annotations = (field["annotations"] as WritableRecord | undefined) ?? {};
    if (tag.shorthand !== undefined) {
      mergePrefixShorthand(annotations, entry, tag.shorthand);
    } else {
      mergeDeep(annotations, boundLeafBodyToObject(tag.children));
    }
    if (Object.keys(annotations).length > 0) {
      field["annotations"] = annotations;
    }
  }

  private nonTagBodyItems(items: readonly BoundTreeItem[]): BoundTreeItem[] {
    return items.filter((item) => item.kind !== BoundNodeKind.BoundTag);
  }

  private promoteSummaryToText(host: WritableRecord): void {
    if (typeof host["summary"] === "string" && host["text"] === undefined) {
      host["text"] = host["summary"];
      delete host["summary"];
    }
  }

  private documentRoot(file: IrFile): WritableRecord {
    switch (file) {
      case IrFile.Product:
        return this.productDoc;
      case IrFile.Module:
        return (this.currentModule?.module.module ?? {}) as WritableRecord;
      case IrFile.Model:
        return (this.currentModule?.model.model ?? {}) as WritableRecord;
      case IrFile.Service:
        return this.serviceRoot ?? {};
      default:
        return {};
    }
  }
}

function workspaceToFileObjects(workspace: WorkspaceIr): Map<string, unknown> {
  const files = new Map<string, unknown>();
  files.set(IrRelativePath.Workspace, workspace);
  files.set(IrRelativePath.Manifest, workspace.manifest);
  files.set(IrRelativePath.Product, workspace.product);

  for (const bundle of workspace.modules) {
    const moduleName = String((bundle.module as { module: Record<string, unknown> }).module["name"]);
    const paths = moduleIrPaths(moduleName);
    files.set(paths.module, bundle.module);
    files.set(paths.model, bundle.model);

    for (const serviceSlice of bundle.services) {
      const stem = serviceFileStem(String((serviceSlice as { service: Record<string, unknown> }).service["name"]));
      const servicePath = serviceIrPath(moduleName, stem);
      files.set(servicePath, serviceSlice);
    }
  }

  return files;
}

import type { IrEmitterSync, IrEmitterInput, IrEmitterResult } from "../ports/ir-emitter.js";

/**
 * Deterministic JSON serialization. Object key order follows the lowering pass
 * insertion order so the same Pactia source yields byte-identical output.
 */
export function emitJson(value: unknown): string {
  return `${JSON.stringify(value, null, 2)}\n`;
}

export class JsonIrEmitter implements IrEmitterSync {
  emit(input: IrEmitterInput): IrEmitterResult {
    return { writtenPaths: [...input.workspace.files.keys()] };
  }
}

export function emitIrFileMap(files: ReadonlyMap<string, unknown>): Map<string, string> {
  const emitted = new Map<string, string>();
  for (const [relativePath, value] of files) {
    emitted.set(relativePath, emitJson(value));
  }
  return emitted;
}

export function stripFieldValue(value: string): string {
  let trimmed = value.trim();
  if (trimmed.endsWith(",")) {
    trimmed = trimmed.slice(0, -1).trim();
  }
  if (trimmed.startsWith('"') && trimmed.endsWith('"')) {
    return trimmed.slice(1, -1);
  }
  return trimmed;
}

export function extractProseLines(body: string): string[] {
  return body
    .split("\n")
    .map((line) => line.trim())
    .filter((line) => line.startsWith(">"))
    .map((line) => line.slice(1).trim());
}

export function proseToGuidance(lines: readonly string[]): string | string[] | undefined {
  if (lines.length === 0) return undefined;
  return lines.length === 1 ? lines[0]! : [...lines];
}

export function proseToText(lines: readonly string[]): string | undefined {
  if (lines.length === 0) return undefined;
  return lines.join("\n");
}

export function serviceFileStem(serviceName: string): string {
  const withoutSuffix = serviceName.endsWith("Service")
    ? serviceName.slice(0, -"Service".length)
    : serviceName;
  return withoutSuffix.replace(/([a-z])([A-Z])/g, "$1-$2").toLowerCase();
}

export function scalarTypeToIr(typeName: string): string {
  const map: Record<string, string> = {
    uuid: "UUID",
    string: "STRING",
    int: "INTEGER",
    integer: "INTEGER",
    decimal: "DECIMAL",
    boolean: "BOOLEAN",
    datetime: "DATETIME",
    json: "JSON",
  };
  return map[typeName.toLowerCase()] ?? typeName.toUpperCase();
}

export function normalizeTopologyMode(mode: string): string {
  const upper = mode.toUpperCase().replace(/-/g, "_");
  if (upper === "MICROSERVICES" || upper === "MODULAR_MONOLITH") return upper;
  return mode;
}

export function normalizeTenancyMode(mode: string): string {
  if (mode.toLowerCase() === "single") return "SINGLE_TENANT";
  if (mode.toLowerCase() === "multi") return "MULTI_TENANT";
  return mode.toUpperCase();
}

export function normalizeDirection(direction: string): string {
  return direction.toUpperCase();
}

export function normalizeAuthType(type: string): string {
  return type.toUpperCase().replace(/-/g, "_");
}

type WritableRecord = Record<string, unknown>;

export function parseScalarValue(raw: string): unknown {
  let trimmed = raw.trim();
  if (trimmed.endsWith(",")) {
    trimmed = trimmed.slice(0, -1).trim();
  }
  if (trimmed.startsWith("[") && trimmed.endsWith("]")) {
    const inner = trimmed.slice(1, -1).trim();
    if (inner.length === 0) return [];
    return inner.split(",").map((part) => parseScalarValue(part.trim()));
  }
  if (trimmed === "true") return true;
  if (trimmed === "false") return false;
  const numeric = Number(trimmed);
  if (Number.isFinite(numeric) && /^-?\d+(\.\d+)?$/.test(trimmed)) return numeric;
  return trimmed.replace(/^["']|["']$/g, "");
}

const IR_ASSIGNMENT = /^([\w.]+):\s*(.+)$/;

export function parseIrAssignmentLine(line: string): { path: string; value: unknown } | undefined {
  const match = IR_ASSIGNMENT.exec(line.trim());
  if (!match) return undefined;
  return { path: match[1]!, value: parseScalarValue(match[2]!) };
}

export function substituteMacroArgs(template: string, args: readonly string[]): string {
  return template.replace(/\{\{(\d+)\}\}/g, (_match, index: string) => args[Number(index)] ?? "");
}

export function getAtPath(root: unknown, path: string): unknown {
  const segments = path.split(".");
  let current: unknown = root;
  for (const segment of segments) {
    if (!current || typeof current !== "object") return undefined;
    current = (current as WritableRecord)[segment];
  }
  return current;
}

export function setAtPath(root: WritableRecord, path: string, value: unknown): void {
  const segments = path.split(".");
  let current: WritableRecord = root;
  for (let index = 0; index < segments.length - 1; index += 1) {
    const segment = segments[index]!;
    const next = current[segment];
    if (!next || typeof next !== "object") {
      const created: WritableRecord = {};
      current[segment] = created;
      current = created;
    } else {
      current = next as WritableRecord;
    }
  }
  current[segments[segments.length - 1]!] = value;
}

export function mergeDeep(target: WritableRecord, patch: WritableRecord): void {
  for (const [key, value] of Object.entries(patch)) {
    const existing = target[key];
    if (
      value &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      existing &&
      typeof existing === "object" &&
      !Array.isArray(existing)
    ) {
      mergeDeep(existing as WritableRecord, value as WritableRecord);
    } else {
      target[key] = value;
    }
  }
}

export function pathPresent(root: unknown, path: string): boolean {
  const value = getAtPath(root, path);
  return value !== undefined && value !== null && value !== "";
}

import { IrMerge } from "../../domain/ir-merge.js";
import type { BoundTreeItem } from "../../domain/bound-tree.js";
import type { RegistryTagEntry } from "../../domain/registry.js";
import { SyntaxNodeKind, type FieldLineNode, type ProseNode, type TagBodyItem } from "../../domain/syntax-tree.js";
import { getAtPath, mergeDeep, parseScalarValue, setAtPath } from "../../lower/ir-path.js";

type WritableRecord = Record<string, unknown>;

export interface ParsedIrPath {
  readonly containerPath: string;
  readonly appendArray: boolean;
}

export function parseIrPath(path: string): ParsedIrPath {
  if (path.endsWith("[]")) {
    return { containerPath: path.slice(0, -2), appendArray: true };
  }
  return { containerPath: path, appendArray: false };
}

export function fieldLinesToObject(lines: readonly FieldLineNode[]): WritableRecord {
  const object: WritableRecord = {};
  for (const line of lines) {
    if (line.required) continue;
    if (line.value === undefined) continue;
    setAtPath(object, line.name, parseScalarValue(line.value));
  }
  return object;
}

type BodyFieldItem = FieldLineNode | ProseNode;

export function tagBodyItemsToObject(items: readonly TagBodyItem[]): WritableRecord {
  const object: WritableRecord = {};
  for (const item of items) {
    if (item.kind === SyntaxNodeKind.FieldLine) {
      if (item.required || item.value === undefined) continue;
      setAtPath(object, item.name, parseScalarValue(item.value));
      continue;
    }
    if (item.kind === SyntaxNodeKind.Prose && item.text.length > 0) {
      object["summary"] = item.text;
    }
  }
  return object;
}

export function boundLeafBodyToObject(items: readonly BoundTreeItem[]): WritableRecord {
  const object: WritableRecord = {};
  const proseLines: string[] = [];
  for (const item of items) {
    if (item.kind === SyntaxNodeKind.FieldLine) {
      appendBodyField(object, item);
      continue;
    }
    if (item.kind === SyntaxNodeKind.Prose && item.text.length > 0) {
      proseLines.push(item.text);
    }
  }
  if (proseLines.length === 1) {
    object["summary"] = proseLines[0];
  } else if (proseLines.length > 1) {
    object["guide"] = proseLines;
  }
  return object;
}

function appendBodyField(object: WritableRecord, item: BodyFieldItem): void {
  if (item.kind !== SyntaxNodeKind.FieldLine) return;
  if (item.required || item.value === undefined) return;
  setAtPath(object, item.name, parseScalarValue(item.value));
}

export function primaryModifierField(entry: RegistryTagEntry): string | undefined {
  if (!entry.modifier) return undefined;
  return entry.fields.required[0] ?? entry.fields.optional[0];
}

export function appendModifierTag(target: WritableRecord, tagName: string): void {
  const existing = target["modifierTags"];
  const tags = Array.isArray(existing) ? [...(existing as string[])] : [];
  if (!tags.includes(tagName)) {
    tags.push(tagName);
  }
  target["modifierTags"] = tags;
}

export function applyRegistryTagLabel(host: WritableRecord, tagName: string): void {
  host["tag"] = tagName;
}

export function appendHostObject(
  root: WritableRecord,
  slotPath: string,
  host: WritableRecord | string,
): void {
  if (slotPath.endsWith("[]")) {
    const arrayPath = slotPath.slice(0, -2);
    const existing = getAtPath(root, arrayPath);
    const array = Array.isArray(existing) ? [...existing] : [];
    array.push(host);
    setAtPath(root, arrayPath, array);
    return;
  }
  setAtPath(root, slotPath, host);
}

export function mergeAtIrPath(root: WritableRecord, slotPath: string, patch: WritableRecord): void {
  const { containerPath, appendArray } = parseIrPath(slotPath);
  if (appendArray) {
    appendHostObject(root, slotPath, patch);
    return;
  }
  const existing = getAtPath(root, containerPath);
  if (existing && typeof existing === "object" && !Array.isArray(existing)) {
    mergeDeep(existing as WritableRecord, patch);
    return;
  }
  setAtPath(root, containerPath, { ...patch });
}

export function mergePrefixShorthand(
  target: WritableRecord,
  entry: RegistryTagEntry,
  shorthand: string,
): void {
  const field = primaryModifierField(entry);
  if (!field) return;
  const basePath = parseIrPath(entry.ir.path).containerPath;
  setAtPath(target, `${basePath}.${field}`, parseScalarValue(shorthand));
}

export function mergeTagBlock(
  target: WritableRecord,
  entry: RegistryTagEntry,
  bodyItems: readonly BoundTreeItem[],
): void {
  const patch = boundLeafBodyToObject(bodyItems);
  if (entry.ir.merge === IrMerge.MergeFields) {
    mergeAtIrPath(target, entry.ir.path, patch);
    return;
  }
  mergeDeep(target, patch);
}

export function collectProse(items: readonly TagBodyItem[]): string | undefined {
  const lines: string[] = [];
  for (const item of items) {
    if (item.kind === SyntaxNodeKind.Prose && item.text.length > 0) {
      lines.push(item.text);
    }
  }
  if (lines.length === 0) return undefined;
  return lines.join("\n");
}

export function collectBlockProse(items: readonly BoundTreeItem[]): string | undefined {
  const lines: string[] = [];
  for (const item of items) {
    if (item.kind === SyntaxNodeKind.Prose && item.text.length > 0) {
      lines.push(item.text);
    }
  }
  if (lines.length === 0) {
    return undefined;
  }
  return lines.join(" ");
}

export function collectServiceProse(items: readonly BoundTreeItem[]): string | undefined {
  return collectBlockProse(items);
}

import { existsSync, readFileSync, readdirSync } from "node:fs";
import { join, resolve } from "node:path";
import type { Diagnostic } from "../../domain/diagnostics.js";
import { DiagnosticCode, createDiagnostic } from "../../domain/index.js";
import {
  SyntaxNodeKind,
  type ModuleNode,
  type ProseNode,
  type ProductNode,
  type ProgramNode,
  type SyntaxTree,
  type TagBodyItem,
} from "../../domain/syntax-tree.js";
import { substituteModuleConstants } from "./substitute-constants.js";

function walkTagBodyItems(
  items: readonly TagBodyItem[],
  constants: ReadonlyMap<string, string>,
  diagnostics: Diagnostic[],
  locationFile: string,
): TagBodyItem[] {
  return items.map((item) => {
    if (item.kind === SyntaxNodeKind.Prose) {
      return substituteProseNode(item, constants, diagnostics, locationFile);
    }
    if (item.kind === SyntaxNodeKind.TagBlock) {
      return {
        ...item,
        items: walkTagBodyItems(item.items, constants, diagnostics, locationFile),
      };
    }
    return item;
  });
}

function substituteProseNode(
  item: ProseNode,
  constants: ReadonlyMap<string, string>,
  diagnostics: Diagnostic[],
  locationFile: string,
): ProseNode {
  const result = substituteModuleConstants(item.text, constants);
  for (const name of result.unresolved) {
    diagnostics.push(
      createDiagnostic(
        DiagnosticCode.ConstantUndefined,
        `Module constant '${name}' is not defined`,
        { target: name, location: { ...item.location, file: locationFile } },
      ),
    );
  }
  return { ...item, text: result.text };
}

function applyToModule(
  module: ModuleNode,
  constants: ReadonlyMap<string, string>,
  diagnostics: Diagnostic[],
): ModuleNode {
  const moduleConstants = new Map(constants);
  for (const item of module.items) {
    if (item.kind === SyntaxNodeKind.ModuleConst) {
      moduleConstants.set(item.name, item.value);
    }
  }

  const items = module.items.map((item) => {
    if (item.kind === SyntaxNodeKind.Service) {
      const serviceConstants = new Map(moduleConstants);
      for (const serviceItem of item.items) {
        if (serviceItem.kind === SyntaxNodeKind.ModuleConst) {
          serviceConstants.set(serviceItem.name, serviceItem.value);
        }
      }
      return {
        ...item,
        items: item.items.map((serviceItem) => {
          if (serviceItem.kind === SyntaxNodeKind.ModuleConst) return serviceItem;
          if (serviceItem.kind === SyntaxNodeKind.Prose) {
            return substituteProseNode(serviceItem, serviceConstants, diagnostics, module.location.file);
          }
          if (serviceItem.kind === SyntaxNodeKind.TagBlock) {
            return {
              ...serviceItem,
              items: walkTagBodyItems(serviceItem.items, serviceConstants, diagnostics, module.location.file),
            };
          }
          return serviceItem;
        }),
      };
    }
    if (item.kind === SyntaxNodeKind.Model) {
      return {
        ...item,
        items: item.items.map((modelItem) => {
          if (modelItem.kind === SyntaxNodeKind.Prose) {
            return substituteProseNode(modelItem, moduleConstants, diagnostics, module.location.file);
          }
          if (modelItem.kind === SyntaxNodeKind.TagBlock) {
            return {
              ...modelItem,
              items: walkTagBodyItems(modelItem.items, moduleConstants, diagnostics, module.location.file),
            };
          }
          return modelItem;
        }),
      };
    }
    if (item.kind === SyntaxNodeKind.TagBlock) {
      return {
        ...item,
        items: walkTagBodyItems(item.items, moduleConstants, diagnostics, module.location.file),
      };
    }
    return item;
  });

  return { ...module, items };
}

function applyToProduct(
  product: ProductNode,
  constants: ReadonlyMap<string, string>,
  diagnostics: Diagnostic[],
): ProductNode {
  const items = product.items.map((item) => {
    if (item.kind === SyntaxNodeKind.Module) {
      return applyToModule(item, constants, diagnostics);
    }
    if (item.kind === SyntaxNodeKind.TagBlock) {
      return {
        ...item,
        items: walkTagBodyItems(item.items, constants, diagnostics, product.location.file),
      };
    }
    if (item.kind === SyntaxNodeKind.Prose) {
      return substituteProseNode(item, constants, diagnostics, product.location.file);
    }
    return item;
  });
  return { ...product, items };
}

export function applyConstantSubstitution(
  tree: SyntaxTree,
  importedConstants: ReadonlyMap<string, string>,
): { readonly tree: SyntaxTree; readonly diagnostics: readonly Diagnostic[] } {
  const diagnostics: Diagnostic[] = [];
  const product = tree.root.product
    ? applyToProduct(tree.root.product, importedConstants, diagnostics)
    : undefined;

  return {
    tree: {
      ...tree,
      root: { ...tree.root, product },
    },
    diagnostics,
  };
}

export function collectExportedConstants(source: string): Map<string, string> {
  const constants = new Map<string, string>();
  const pattern = /export\s+def\s+(\w+)\s*=\s*(.+)$/gm;
  let match: RegExpExecArray | null = pattern.exec(source);
  while (match) {
    constants.set(match[1]!, match[2]!.trim());
    match = pattern.exec(source);
  }
  return constants;
}

export function importedConstantsFromProgram(program: ProgramNode, workspaceRoot: string): Map<string, string> {
  const constants = new Map<string, string>();

  for (const imp of program.imports) {
    if (!imp.symbols) continue;

    if (imp.path.startsWith("@")) {
      // Package import: read from vendored index.pactia
      const vendoredDir = imp.path.replace(/\//g, "--");
      // Try all vendored version dirs under .pactia/packages/
      const packagesRoot = join(workspaceRoot, ".pactia", "packages");
      if (!existsSync(packagesRoot)) continue;
      const dirs = readdirSync(packagesRoot, { withFileTypes: true })
        .filter((d) => d.isDirectory() && d.name.startsWith(vendoredDir + "@"))
        .map((d) => join(packagesRoot, d.name));
      for (const dir of dirs) {
        const indexPath = join(dir, "index.pactia");
        if (!existsSync(indexPath)) continue;
        const pkgConstants = collectExportedConstants(readFileSync(indexPath, "utf8"));
        for (const symbol of imp.symbols) {
          const name = symbol.replace(/^[@#]+/, "");
          const value = pkgConstants.get(name);
          if (value !== undefined) constants.set(name, value);
        }
      }
    } else {
      const filePath = resolve(workspaceRoot, imp.path);
      if (!existsSync(filePath)) continue;
      const fileConstants = collectExportedConstants(readFileSync(filePath, "utf8"));
      for (const symbol of imp.symbols) {
        const name = symbol.replace(/^[@#]+/, "");
        const value = fileConstants.get(name);
        if (value !== undefined) constants.set(name, value);
      }
    }
  }

  return constants;
}

import { SyntaxNodeKind, type ModuleNode, type ModuleConstNode } from "../../domain/syntax-tree.js";

const INTERPOLATION_PATTERN = /\$\{([A-Za-z_][A-Za-z0-9_]*)\}/g;

export function substituteModuleConstants(
  text: string,
  constants: ReadonlyMap<string, string>,
): { readonly text: string; readonly unresolved: readonly string[] } {
  const unresolved = new Set<string>();
  const replaced = text.replace(INTERPOLATION_PATTERN, (match, name: string) => {
    const value = constants.get(name);
    if (value === undefined) {
      unresolved.add(name);
      return match;
    }
    return value;
  });
  return { text: replaced, unresolved: [...unresolved] };
}

export function moduleConstantsFromModules(modules: readonly ModuleNode[]): Map<string, string> {
  const constants = new Map<string, string>();
  for (const module of modules) {
    for (const item of module.items) {
      if (item.kind === SyntaxNodeKind.ModuleConst) {
        constants.set(item.name, (item as ModuleConstNode).value);
      }
    }
  }
  return constants;
}

import type { Diagnostic } from "../../domain/diagnostics.js";
import { DiagnosticCode, createDiagnostic } from "../../domain/index.js";
import { parseImportSymbol, ImportSymbolKind } from "../registry/import-symbol.js";
import { FragmentExportKind } from "../../frontend/workspace/attach-merge.js";

const ATTACH_MODULE = /module\s*\(\s*(\w+)\s*\)\s*\{/g;
const ATTACH_SERVICE = /service\s*\(\s*(\w+)\s*\)/g;
const ATTACH_MODEL = /model\s*\(\s*(\w+)\s*\)/g;
const PARTIAL_IMPORT = /import\s*\{([^}]+)\}\s+from\s+([^;]+);/g;
const TAG_USE = /@([A-Za-z_][\w]*)/g;
const MODIFIER_USE = /@@([A-Za-z_][\w]*)/g;
const MACRO_USE = /#([A-Za-z_][\w]*)\s*(?:\(|$|\{)/gm;

export function collectImportUnusedDiagnostics(
  productSource: string,
  entryFile: string,
): readonly Diagnostic[] {
  const diagnostics: Diagnostic[] = [];
  const usedTags = new Set<string>();
  const usedModifiers = new Set<string>();
  const usedMacros = new Set<string>();
  const usedConstants = new Set<string>();

  let tagMatch: RegExpExecArray | null = TAG_USE.exec(productSource);
  while (tagMatch) {
    usedTags.add(tagMatch[1]!);
    tagMatch = TAG_USE.exec(productSource);
  }

  let modMatch: RegExpExecArray | null = MODIFIER_USE.exec(productSource);
  while (modMatch) {
    usedModifiers.add(modMatch[1]!);
    modMatch = MODIFIER_USE.exec(productSource);
  }

  let macroMatch: RegExpExecArray | null = MACRO_USE.exec(productSource);
  while (macroMatch) {
    usedMacros.add(macroMatch[1]!);
    macroMatch = MACRO_USE.exec(productSource);
  }

  let attachMatch: RegExpExecArray | null = ATTACH_MODULE.exec(productSource);
  while (attachMatch) {
    usedConstants.add(attachMatch[1]!);
    attachMatch = ATTACH_MODULE.exec(productSource);
  }

  attachMatch = ATTACH_SERVICE.exec(productSource);
  while (attachMatch) {
    usedConstants.add(attachMatch[1]!);
    attachMatch = ATTACH_SERVICE.exec(productSource);
  }

  attachMatch = ATTACH_MODEL.exec(productSource);
  while (attachMatch) {
    usedConstants.add(attachMatch[1]!);
    attachMatch = ATTACH_MODEL.exec(productSource);
  }

  const constantPattern = /\$\{([A-Za-z_][\w]*)\}/g;
  let constUse: RegExpExecArray | null = constantPattern.exec(productSource);
  while (constUse) {
    usedConstants.add(constUse[1]!);
    constUse = constantPattern.exec(productSource);
  }

  let importMatch: RegExpExecArray | null = PARTIAL_IMPORT.exec(productSource);
  while (importMatch) {
    const symbolList = importMatch[1]!;
    const rawPath = importMatch[2]!.trim();
    if (rawPath.startsWith("@")) {
      for (const raw of symbolList.split(",").map((part) => part.trim()).filter(Boolean)) {
        const parsed = parseImportSymbol(raw);
        const used =
          (parsed.kind === ImportSymbolKind.Tag && usedTags.has(parsed.name)) ||
          (parsed.kind === ImportSymbolKind.ModifierTag && usedModifiers.has(parsed.name)) ||
          (parsed.kind === ImportSymbolKind.Macro && usedMacros.has(parsed.name)) ||
          (parsed.kind === ImportSymbolKind.Constant && usedConstants.has(parsed.name));
        if (!used) {
          diagnostics.push(
            createDiagnostic(
              DiagnosticCode.ImportUnused,
              `Partial import symbol '${raw}' is never referenced`,
              { target: raw, location: { file: entryFile, line: 1, col: 1 } },
            ),
          );
        }
      }
    }
    importMatch = PARTIAL_IMPORT.exec(productSource);
  }

  return diagnostics;
}

export function attachKindMismatchDiagnostic(
  symbol: string,
  expected: FragmentExportKind,
  actual: FragmentExportKind,
  filePath: string,
): Diagnostic {
  return createDiagnostic(
    DiagnosticCode.AttachKindMismatch,
    `Attach kind mismatch for '${symbol}': expected ${expected}, got ${actual}`,
    { target: symbol, location: { file: filePath, line: 1, col: 1 } },
  );
}

export function attachUndefinedDiagnostic(symbol: string, filePath: string): Diagnostic {
  return createDiagnostic(
    DiagnosticCode.AttachUndefined,
    `Attach references undefined symbol '${symbol}'`,
    { target: symbol, location: { file: filePath, line: 1, col: 1 } },
  );
}

const FRAGMENT_PACKAGE_IMPORT =
  /^\s*import\s+(?:\{\s*[^}]*\s*\}\s+from\s+)?(@\S+)\s*;/;

/** Warn on package imports in fragment files — they are ignored; product.pactia owns @ imports. */
export function collectFragmentPackageImportDiagnostics(
  filePath: string,
  source: string,
): readonly Diagnostic[] {
  const diagnostics: Diagnostic[] = [];
  const lines = source.split("\n");
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index]!;
    const match = FRAGMENT_PACKAGE_IMPORT.exec(line);
    if (!match) continue;
    const coordinate = match[1]!;
    diagnostics.push(
      createDiagnostic(
        DiagnosticCode.FragmentPackageImport,
        `Package import '${coordinate}' in a fragment is ignored — declare package imports in product.pactia only`,
        {
          target: coordinate,
          location: { file: filePath, line: index + 1, col: 1 },
        },
      ),
    );
  }
  return diagnostics;
}
